  procRelatorio.cboTabela.innerHTML=baseTabelas.map(x=>`<option value="${esc(String(x.id??""))}">${esc(String(x.nome??""))}</option>`).join("");
  procSetSelectValue(procRelatorio.cboTabela,String(proc.cboTabela?.value||baseTabelas[0]?.id||""));
  procRelatorio.cboEspecialidade.innerHTML=['<option value="">Todas</option>',...especialidades.map(x=>`<option value="${esc(String(x.codigo??""))}">${esc(String(x.nome??""))}</option>`)].join("");
