function procRelatorioLinhasPorPaginaMedida(){
  if(!procRelatorioView?.sheet||!procRelatorioView?.tbody)return null;
  const sheet=procRelatorioView.sheet;
  const firstRow=procRelatorioView.tbody.querySelector("tr");
  if(!firstRow)return null;
  const sheetRect=sheet.getBoundingClientRect();
  const bodyRect=procRelatorioView.tbody.getBoundingClientRect();
  const rowRect=firstRow.getBoundingClientRect();
  const rowH=rowRect.height||0;
  if(!rowH)return null;
  const estilo=window.getComputedStyle(sheet);
  const padBottom=parseFloat(estilo.paddingBottom||"0")||0;
  const bottomLimit=sheetRect.bottom-padBottom;
  const avail=bottomLimit-bodyRect.top;
  if(!Number.isFinite(avail)||avail<=0)return null;
  const linhas=Math.floor(avail/rowH);
  return Math.max(6,linhas);
}
function procRelatorioLinhasPorPagina(){
  if(procRelatorioView&&Number.isFinite(procRelatorioView._linhasPorPagina)&&procRelatorioView._linhasPorPagina>0){
    return procRelatorioView._linhasPorPagina;
  }
  const medida=procRelatorioLinhasPorPaginaMedida();
  if(medida)return medida;
  const alturaFolha=procRelatorioView?.orientacao==="paisagem"?794:1123;
  const alturaCabecalho=96;
  const alturaRodape=42;
  const margemVertical=78;
  const alturaLinha=18;
  const alturaUtil=alturaFolha-(alturaCabecalho+alturaRodape+margemVertical);
  return Math.max(8,Math.floor(alturaUtil/alturaLinha));
}
function procRelatorioAjustarLinhasPorEspaco(rows,linhasPorPagina){
  if(!procRelatorioView?.sheet||!procRelatorioView?.tbody||!rows?.length)return null;
  const lastRow=procRelatorioView.tbody.querySelector("tr:last-child");
  if(!lastRow)return null;
  const sheet=procRelatorioView.sheet;
  const style=window.getComputedStyle(sheet);
  const padBottom=parseFloat(style.paddingBottom||"0")||0;
  const sheetRect=sheet.getBoundingClientRect();
  const lastRect=lastRow.getBoundingClientRect();
  const lastBottom=lastRect.bottom;
  let rowH=lastRow.offsetHeight;
  if(!rowH){
    const cell=lastRow.querySelector("td,th");
    if(cell)rowH=parseFloat(window.getComputedStyle(cell).lineHeight||"0")||0;
  }
  if(!rowH)return null;
  const bottomLimit=sheetRect.bottom-padBottom;
  const free=bottomLimit-lastBottom;
  const ini=(procRelatorioView.pagina-1)*linhasPorPagina;
  const remaining=Math.max(0,rows.length-(ini+linhasPorPagina));
  if(remaining<=0)return null;
  const extra=Math.floor(free/rowH);
  if(extra>0)return linhasPorPagina+extra;
  if(free< -rowH){
    const reduce=Math.ceil(Math.abs(free)/rowH);
    return Math.max(6,linhasPorPagina-reduce);
  }
  return null;
}
function procRelatorioAtualizarZoom(){
  if(!procRelatorioView?.sheet||!procRelatorioView?.zoom)return;
  const valor=Math.max(50,Math.min(200,Number(procRelatorioView.zoom.value||100)));
  procRelatorioView.zoom.value=String(valor);
  procRelatorioView.zoomLabel.textContent=`${valor}%`;
  const scale=valor/100;
  procRelatorioView.sheet.style.transform=`scale(${scale})`;
  procRelatorioView.sheetHolder.style.height=`${Math.ceil(procRelatorioView.baseSheetHeight*scale)+36}px`;
}
function procRelatorioPreviewEmpilhado(campos){
  if(!Array.isArray(campos))return false;
  const orientacao=procRelatorioView?.orientacao==="paisagem"?"paisagem":"retrato";
  const limite=orientacao==="paisagem"?10:6;
  return campos.length>limite
}
function procRelatorioSplitCamposEmpilhados(campos){
  const base=Array.isArray(campos)?campos:[];
  if(base.length<=1)return{primeiro:base[0]||"",bandas:[[{top:"",bottom:""}]],linhas:1,maxCols:1};
  const orientacao=procRelatorioView?.orientacao==="paisagem"?"paisagem":"retrato";
  const resto=base.slice(1);
  const pares=[];
  for(let idx=0;idx<resto.length;idx+=2){
    pares.push({top:resto[idx]||"",bottom:resto[idx+1]||""});
  }
  const limiteParesPorBanda=orientacao==="paisagem"?8:5;
  const bandas=[];
  for(let idx=0;idx<pares.length;idx+=limiteParesPorBanda){
    bandas.push(pares.slice(idx,idx+limiteParesPorBanda));
  }
  return{primeiro:base[0]||"",bandas:bandas.length?bandas:[[ {top:"",bottom:""} ]],linhas:Math.max(1,bandas.length*2),maxCols:Math.max(...(bandas.length?bandas.map(banda=>banda.length):[1]))}
}
function procRelatorioRenderPagina(){
  if(!procRelatorioView)return;
  const campos=procRelatorioView.campos||[];
  const rows=procRelatorioView.rows||[];
  const cfg=procRelatorioView.config||procRelatorioConfigAtual();
  const linhasPorPagina=procRelatorioLinhasPorPagina();
  procRelatorioView._linhasPorPagina=linhasPorPagina;
  const totalPaginas=Math.max(1,Math.ceil(rows.length/linhasPorPagina));
  procRelatorioView.pagina=Math.max(1,Math.min(totalPaginas,Number(procRelatorioView.pag?.value||procRelatorioView.pagina||1)));
  if(procRelatorioView.pag){
    procRelatorioView.pag.max=String(totalPaginas);
    procRelatorioView.pag.value=String(procRelatorioView.pagina);
  }
  if(procRelatorioView.pagTotal)procRelatorioView.pagTotal.textContent=`de ${totalPaginas}`;
  const dataAgora=new Date();
  if(procRelatorioView.date)procRelatorioView.date.textContent=cfg?.printDateTime?`Data: ${dataAgora.toLocaleDateString("pt-BR")}`:"";
  if(procRelatorioView.time)procRelatorioView.time.textContent=cfg?.printDateTime?`Hora: ${dataAgora.toLocaleTimeString("pt-BR",{hour:"2-digit",minute:"2-digit"})}`:"";
  if(procRelatorioView.pageMeta)procRelatorioView.pageMeta.textContent=cfg?.printPage?`Pág.: ${procRelatorioView.pagina}`:"";
  if(procRelatorioView.title)procRelatorioView.title.textContent=procRelatorioView.titulo||"Relatório";
  if(procRelatorioView.headCaption)procRelatorioView.headCaption.textContent=String(cfg?.headerText||"").trim();
  if(procRelatorioView.user){
    const usuarioAtual=relatorioUsuarioAtual();
    const showUser=cfg?.printUser&&usuarioAtual;
    procRelatorioView.user.textContent=showUser?`Usuário: ${usuarioAtual}`:"";
    procRelatorioView.user.style.display=showUser?"block":"none";
  }
  if(procRelatorioView.logo){
    const logoSrc=String(cfg?.logoDataUrl||"").trim();
    procRelatorioView.logo.style.display=cfg?.printLogo&&logoSrc?"block":"none";
    if(cfg?.printLogo&&logoSrc)procRelatorioView.logo.src=logoSrc;
  }
  if(procRelatorioView.sheet){
    const pxPorCm=37.8;
    const top=Math.max(18,Math.round(Number(cfg?.marginTopCm||1)*pxPorCm));
    const right=Math.max(18,Math.round(Number(cfg?.marginRightCm||1)*pxPorCm));
    const bottom=Math.max(18,Math.round(Number(cfg?.marginBottomCm||1)*pxPorCm));
    const left=Math.max(18,Math.round(Number(cfg?.marginLeftCm||1)*pxPorCm));
    procRelatorioView.sheet.style.padding=`${top}px ${right}px ${bottom}px ${left}px`;
  }
  const estiloTitulo=cfg?.sectionStyles?.titulo;
  if(procRelatorioView.title&&estiloTitulo){
    procRelatorioView.title.style.fontSize=`${Number(estiloTitulo.fontSize||11)}px`;
    procRelatorioView.title.style.fontWeight=estiloTitulo.bold?"700":"400";
    procRelatorioView.title.style.color=estiloTitulo.color||"#111111";
  }
  if(procRelatorioView.note){
    const note=String(procRelatorioView.observacao||"").trim();
    procRelatorioView.note.textContent=note;
    procRelatorioView.note.style.display=note?"block":"none";
  }
  const ini=(procRelatorioView.pagina-1)*linhasPorPagina;
  const fim=Math.min(rows.length,ini+linhasPorPagina);
  const paginaRows=rows.slice(ini,fim);
  const empilhado=procRelatorioPreviewEmpilhado(campos);
  const tabelaEl=procRelatorioView.thead?.closest("table");
  if(tabelaEl){
    tabelaEl.classList.toggle("stack-preview",empilhado);
    tabelaEl.classList.toggle("stack-portrait",empilhado&&procRelatorioView?.orientacao!=="paisagem");
    tabelaEl.classList.toggle("stack-landscape",empilhado&&procRelatorioView?.orientacao==="paisagem");
    let colgroup=tabelaEl.querySelector("colgroup");
    if(empilhado){
      const partesPreview=procRelatorioSplitCamposEmpilhados(campos);
      const colsHtml=`<col class="first-col">${Array.from({length:Math.max(1,partesPreview.maxCols||1)},()=>'<col class="data-col">').join("")}`;
      if(!colgroup){
        colgroup=document.createElement("colgroup");
        tabelaEl.insertBefore(colgroup,tabelaEl.firstChild);
      }
      colgroup.innerHTML=colsHtml;
    }else if(colgroup){
      colgroup.remove();
    }
  }
  if(empilhado){
    const partes=procRelatorioSplitCamposEmpilhados(campos);
    const linhasCabecalho=(partes.bandas||[]).map((banda,bandaIdx)=>{
      const blanks=Math.max(0,(partes.maxCols||0)-banda.length);
      const primeiraTop=bandaIdx===0?`<th class="first-col" rowspan="${Math.max(1,partes.linhas)}">${esc(partes.primeiro)}</th>`:"";
      const top=`<tr class="${bandaIdx===0?"top-head":"sub-head"}">${primeiraTop}${banda.map(par=>`<th class="${procRelatorioClasseCampo(par.top)}">${esc(par.top||"")}</th>`).join("")}${Array.from({length:blanks},()=>'<th class="blank"></th>').join("")}</tr>`;
      const sub=`<tr class="sub-head">${bandaIdx===0?"":""}${banda.map(par=>`<th class="${!par.bottom?"blank":procRelatorioClasseCampo(par.bottom)}">${esc(par.bottom||"")}</th>`).join("")}${Array.from({length:blanks},()=>'<th class="blank"></th>').join("")}</tr>`;
      return `${top}${sub}`;
    }).join("");
    if(procRelatorioView.thead){
      procRelatorioView.thead.innerHTML=linhasCabecalho;
    }
    if(procRelatorioView.tbody){
      procRelatorioView.tbody.innerHTML=paginaRows.length?paginaRows.map(row=>{
        return (partes.bandas||[]).map((banda,bandaIdx,bandas)=>{
          const blanks=Math.max(0,(partes.maxCols||0)-banda.length);
          const topCls=`${bandaIdx===0?"main-row":"sub-row"}`.trim();
          const bottomCls=`sub-row ${bandaIdx===bandas.length-1?"group-end":""}`.trim();
          const primeiraTop=bandaIdx===0?`<td class="first-col" rowspan="${Math.max(1,partes.linhas)}">${esc(procRelatorioFormatarCampo(partes.primeiro,procRelatorioValorCampo(row,partes.primeiro)))}</td>`:"";
          const top=`<tr class="${topCls}">${primeiraTop}${banda.map(par=>`<td class="${procRelatorioClasseCampo(par.top)}">${esc(procRelatorioFormatarCampo(par.top,procRelatorioValorCampo(row,par.top)))}</td>`).join("")}${Array.from({length:blanks},()=>'<td class="blank"></td>').join("")}</tr>`;
          const bottom=`<tr class="${bottomCls}">${banda.map(par=>{const campo=par.bottom||"";return campo?`<td class="${procRelatorioClasseCampo(campo)}">${esc(procRelatorioFormatarCampo(campo,procRelatorioValorCampo(row,campo)))}</td>`:'<td class="blank"></td>'}).join("")}${Array.from({length:blanks},()=>'<td class="blank"></td>').join("")}</tr>`;
          return `${top}${bottom}`;
        }).join("");
      }).join(""):`<tr><td class="proc-rview-empty" colspan="${Math.max(1,campos.length)}">Sem dados.</td></tr>`;
    }
  procRelatorioAplicarEstilosConfig();
  if(!procRelatorioView._ajustandoLinhas){
    const medida=procRelatorioLinhasPorPaginaMedida();
    let novoValor=null;
    if(medida&&medida!==linhasPorPagina)novoValor=medida;
    if(!novoValor){
      const ajuste=procRelatorioAjustarLinhasPorEspaco(rows,linhasPorPagina);
      if(ajuste&&ajuste!==linhasPorPagina)novoValor=ajuste;
    }
    if(novoValor){
      procRelatorioView._ajustandoLinhas=true;
      procRelatorioView._linhasPorPagina=novoValor;
      procRelatorioRenderPagina();
      procRelatorioView._ajustandoLinhas=false;
      return;
    }
  }
  return;
}
  if(procRelatorioView.thead)procRelatorioView.thead.innerHTML=`<tr>${campos.map(c=>`<th class="${procRelatorioClasseCampo(c)}">${esc(c)}</th>`).join("")}</tr>`;
  if(procRelatorioView.tbody){
    procRelatorioView.tbody.innerHTML=paginaRows.length?paginaRows.map(row=>`<tr>${campos.map(c=>`<td class="${procRelatorioClasseCampo(c)}">${esc(procRelatorioFormatarCampo(c,procRelatorioValorCampo(row,c)))}</td>`).join("")}</tr>`).join(""):`<tr><td class="proc-rview-empty" colspan="${Math.max(1,campos.length)}">Sem dados.</td></tr>`;
  }
  procRelatorioAplicarEstilosConfig();
}
function procRelatorioAbrirPreview(campos,rows,titulo,note,opts={}){
  procRelatorioEnsurePreviewUI();
  procRelatorioView.onBack=typeof opts?.onBack==="function"?opts.onBack:null;
  procRelatorioView.onClose=typeof opts?.onClose==="function"?opts.onClose:null;
  procRelatorioView.onPrint=typeof opts?.onPrint==="function"?opts.onPrint:null;
  procRelatorioView.campos=[...(campos||[])];
  procRelatorioView.rows=Array.isArray(rows)?rows:[];
  procRelatorioView.titulo=titulo||"Relatório de tabela de procedimentos";
  procRelatorioView.observacao=note||"";
  procRelatorioView._linhasPorPagina=null;
  procRelatorioView.config=procRelatorioConfigAtual();
  const orientacao=opts?.orientacao|| (procRelatorio?.radPaisagem?.checked?"paisagem":"retrato");
  procRelatorioView.orientacao=orientacao;
  procRelatorioView.baseSheetHeight=procRelatorioView.orientacao==="paisagem"?794:1123;
  if(procRelatorioView.sheet){
    procRelatorioView.sheet.classList.toggle("landscape",procRelatorioView.orientacao==="paisagem");
    procRelatorioView.sheet.classList.toggle("portrait",procRelatorioView.orientacao!=="paisagem");
  }
  procRelatorioView.pagina=1;
  if(procRelatorioView.pag)procRelatorioView.pag.value="1";
  if(procRelatorio?.backdrop)procRelatorio.backdrop.classList.add("hidden");
  if(proc.panel)proc.panel.classList.add("hidden");
  procRelatorioView.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
  procRelatorioAtualizarZoom();
  procRelatorioRenderPagina();
}
function procRelatorioVoltarFiltros(){
  if(procRelatorioView?.panel)procRelatorioView.panel.classList.add("hidden");
  if(proc.panel)proc.panel.classList.remove("hidden");
  if(procRelatorio?.backdrop)procRelatorio.backdrop.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
}
function procRelatorioFecharPreview(){
  if(procRelatorioView?.panel)procRelatorioView.panel.classList.add("hidden");
  if(proc.panel)proc.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
}
function procRelatorioMontarHtml(campos,rows,titulo){
  const cfg=relatorioConfigAtual();
  const {data,hora}=relatorioDataHoraAtual();
  const usuario=relatorioUsuarioAtual();
  const logoSrc=cfg?.printLogo?String(cfg?.logoDataUrl||"").trim():"";
  const cssTitulo=relatorioCssFromStyle(cfg?.sectionStyles?.titulo,{fontFamily:"Tahoma",fontSize:16,bold:true});
  const cssCab=relatorioCssFromStyle(cfg?.sectionStyles?.cabecalho,{fontFamily:"Tahoma",fontSize:10,bold:true});
  const cssCol=relatorioCssFromStyle(cfg?.sectionStyles?.colunas,{fontFamily:"Tahoma",fontSize:10,bold:true});
  const cssCorpo=relatorioCssFromStyle(cfg?.sectionStyles?.corpo,{fontFamily:"Tahoma",fontSize:10});
  const cssRod=relatorioCssFromStyle(cfg?.sectionStyles?.rodape,{fontFamily:"Tahoma",fontSize:10});
  const mTop=Number(cfg?.marginTopCm||1);
  const mRight=Number(cfg?.marginRightCm||1);
  const mBottom=Number(cfg?.marginBottomCm||1);
  const mLeft=Number(cfg?.marginLeftCm||1);
  const pageW=Number(cfg?.paperWidthCm||21);
  const pageH=Number(cfg?.paperHeightCm||29.7);
  const showUser=cfg?.printUser&&usuario;
  const showDateTime=cfg?.printDateTime;
  const showPage=cfg?.printPage;
  const headerHtml=`<div class="rel-header">
    <div class="rel-header-left">
      <img class="rel-logo" src="${esc(logoSrc)}" alt="" style="display:${logoSrc?"block":"none"}">
      <div class="rel-head-text">
        ${cfg?.headerText?`<div class="rel-head-caption">${esc(cfg.headerText)}</div>`:""}
        <div class="rel-title">${esc(titulo||"Relatório")}</div>
        ${showUser?`<div class="rel-user">Usuário: ${esc(usuario)}</div>`:""}
      </div>
    </div>
    <div class="rel-meta" style="${cssCab}">
      ${showDateTime?`<div>Data: ${esc(data)}</div><div>Hora: ${esc(hora)}</div>`:""}
      ${showPage?`<div>Pág.: 1</div>`:""}
    </div>
  </div>`;
  const bodyRows=(rows||[]).length?(rows||[]).map(row=>`<tr>${campos.map(c=>`<td class="${procRelatorioClasseCampo(c)}">${esc(procRelatorioFormatarCampo(c,procRelatorioValorCampo(row,c)))}</td>`).join("")}</tr>`).join(""):`<tr><td colspan="${Math.max(1,campos.length)}" style="text-align:center">Sem dados.</td></tr>`;
  return`<!doctype html><html lang="pt-BR"><head><meta charset="utf-8"><title>${esc(titulo||"Relatório")}</title><style>
    @page { size: ${pageW}cm ${pageH}cm; margin: ${mTop}cm ${mRight}cm ${mBottom}cm ${mLeft}cm; }
    body{margin:${mTop}cm ${mRight}cm ${mBottom}cm ${mLeft}cm;font-family:Tahoma,Arial,sans-serif;font-size:11px;color:#000}
    .rel-header{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:8px}
    .rel-header-left{display:flex;gap:8px;align-items:flex-start;min-width:0}
    .rel-logo{width:48px;height:48px;object-fit:contain}
    .rel-head-caption{${cssCab}}
    .rel-title{${cssTitulo}}
    .rel-user{${cssCab}}
    .rel-meta{display:flex;gap:12px;align-items:flex-start;justify-content:flex-end;flex-wrap:wrap}
    table{width:100%;border-collapse:collapse}
    th{${cssCol};padding:3px 4px;border-bottom:1px solid #000;text-align:left;white-space:nowrap}
    th.money{text-align:right}
    th.center,td.center{text-align:center}
    td{${cssCorpo};padding:3px 4px;border-bottom:1px solid #ddd;white-space:nowrap}
    td.money{text-align:right}
    tfoot td{${cssRod}}
  </style></head><body>${headerHtml}<table><thead><tr>${campos.map(c=>`<th class="${procRelatorioClasseCampo(c)}">${esc(c)}</th>`).join("")}</tr></thead><tbody>${bodyRows}</tbody></table></body></html>`;
}
function procRelatorioAbrirDialogoImpressao(campos,rows,titulo){const html=procRelatorioMontarHtml(campos,rows,titulo);const frame=document.createElement("iframe");frame.style.position="fixed";frame.style.right="0";frame.style.bottom="0";frame.style.width="0";frame.style.height="0";frame.style.border="0";document.body.appendChild(frame);const win=frame.contentWindow;const doc=win?.document;if(!doc){frame.remove();window.alert("Não foi possível iniciar a impressão.");return false}doc.open();doc.write(html);doc.close();let printed=false;const doPrint=()=>{if(printed)return;printed=true;try{win.focus();win.print()}catch{}};frame.onload=doPrint;setTimeout(doPrint,180);const cleanup=()=>{setTimeout(()=>{try{frame.remove()}catch{}},1200)};try{win.addEventListener("afterprint",cleanup)}catch{}setTimeout(cleanup,60000);return true}
function procRelatorioExportarArquivo(campos,rows,titulo){const linhas=[];linhas.push(campos.join(";"));(rows||[]).forEach(row=>{linhas.push(campos.map(c=>`"${String(procRelatorioFormatarCampo(c,procRelatorioValorCampo(row,c))||"").replace(/"/g,'""')}"`).join(";"))});const conteudo="\ufeff"+linhas.join("\r\n");const blob=new Blob([conteudo],{type:"text/csv;charset=utf-8;"});const url=URL.createObjectURL(blob);const nome=(titulo||"relatorio_tabela_procedimentos").normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-zA-Z0-9_-]+/g,"_").replace(/_+/g,"_").replace(/^_+|_+$/g,"").toLowerCase()||"relatorio_tabela_procedimentos";const a=document.createElement("a");a.href=url;a.download=`${nome}.csv`;document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(url)}
function procRelatorioImprimirPreview(){
  const campos=procRelatorioView?.campos||[];
  const rows=procRelatorioView?.rows||[];
  const titulo=procRelatorioView?.titulo||"Relatório";
  if(!campos.length)return;
  procRelatorioAbrirDialogoImpressao(campos,rows,titulo);
}
