function cnfRelatorioAbrir(opts={}){
  cnfRelatorioEnsureUI();
  cnfRelatorio.context=cnfRelatorioResolverContexto(opts?.targetUser||null,opts?.origin||"menu");
  if(cnfRelatorio?.btnImpressora){
    const novoBotao=cnfRelatorio.btnImpressora.cloneNode(true);
    cnfRelatorio.btnImpressora.replaceWith(novoBotao);
    cnfRelatorio.btnImpressora=novoBotao;
    cnfRelatorio.btnImpressora.addEventListener("click",cnfRelatorioAbrirDlgImpressora);
  }
  if(cnfRelatorio?.btnFonte){
    const novoBotaoFonte=cnfRelatorio.btnFonte.cloneNode(true);
    cnfRelatorio.btnFonte.replaceWith(novoBotaoFonte);
    cnfRelatorio.btnFonte=novoBotaoFonte;
    cnfRelatorio.btnFonte.addEventListener("click",cnfRelatorioAlterarFonte);
  }
  if(cnfRelatorio?.btnTeste){
    const novoBotaoTeste=cnfRelatorio.btnTeste.cloneNode(true);
    cnfRelatorio.btnTeste.replaceWith(novoBotaoTeste);
    cnfRelatorio.btnTeste=novoBotaoTeste;
    cnfRelatorio.btnTeste.addEventListener("click",cnfRelatorioAbrirDlgTeste);
  }
  if(cnfRelatorio?.btnOk){
    const novoBotaoOk=cnfRelatorio.btnOk.cloneNode(true);
    cnfRelatorio.btnOk.replaceWith(novoBotaoOk);
    cnfRelatorio.btnOk=novoBotaoOk;
    cnfRelatorio.btnOk.addEventListener("click",async()=>{cnfRelatorioSalvarPapel();const resultado=await cnfRelatorioSalvarServidor();if(!resultado.ok){window.alert(resultado.message||"Falha ao salvar a configuração de impressos.");return}cnfRelatorio.state=resultado.config||cnfRelatorio.state;cnfRelatorioSalvarEstado();cnfRelatorio.backdrop.classList.add("hidden");const ctx=cnfRelatorioContextoAtual();footerMsg.textContent=`Configuração de relatórios atualizada para ${ctx.userApelido||ctx.userNome||"o usuário"}.`});
  }
  cnfRelatorio.state=cnfRelatorioCarregarLocal();
  cnfRelatorioSelecionarAba("relatorios");
  cnfRelatorioSincronizarUI();
  cnfRelatorio.backdrop.classList.remove("hidden");
  cnfRelatorioCarregarServidor().then(config=>{if(!config||!cnfRelatorio)return;cnfRelatorio.state=config;cnfRelatorioSalvarEstado();cnfRelatorioSincronizarUI()});
}
const ETQ_PADRAO_ARQUIVO_MAP={
  1:"Envelope.mod",
  2:"Envelope.mod",
  3:"Envelope.mod",
  4:"Pimaco6080.mod",
  5:"Pimaco6081.mod",
  6:"PimacoA4254.mod",
  7:"PimacoA4255.mod",
  8:"PimacoA4256.mod",
};
function etqNumero(valor,padrao){const num=Number(String(valor||"").replace(",","."));return Number.isFinite(num)?num:padrao}
function etqFormatNumero(valor){const num=Number(valor);if(!Number.isFinite(num))return"";return num.toFixed(2).replace(".",",")}
function etqSelecionarLinha(tr){if(!etqCfg||!tr)return;const id=Number(tr.dataset.id||0)||0;etqCfg.selectedId=id;etqCfg.tbody.querySelectorAll("tr").forEach(row=>row.classList.toggle("selected",Number(row.dataset.id||0)===id))}
function etqSelecionado(){if(!etqCfg)return null;return (etqCfg.modelos||[]).find(item=>Number(item.id||0)===Number(etqCfg.selectedId||0))||null}
function etqArquivosOrdenados(){
  const itens=Array.isArray(etqCfg?.arquivos)?etqCfg.arquivos:[];
  const mapa=new Map();
  itens.forEach(item=>{
    const key=String(item?.nome_arquivo||item?.nome||"").trim().toLowerCase();
    if(!key)return;
    const atual=mapa.get(key);
    if(!atual){mapa.set(key,item);return}
    const atualClinica=atual?.clinica_id!=null;
    const novoClinica=item?.clinica_id!=null;
    if(!atualClinica&&novoClinica)mapa.set(key,item);
  });
  return Array.from(mapa.values()).sort((a,b)=>String(a.nome_arquivo||a.nome||"").localeCompare(String(b.nome_arquivo||b.nome||""),"pt-BR"));
}
function etqResolverArquivoPadrao(padraoId){
  const alvo=ETQ_PADRAO_ARQUIVO_MAP[Number(padraoId||0)]||"";
  const lista=etqArquivosOrdenados();
  if(alvo){
    const found=lista.find(item=>String(item.nome_arquivo||"").toLowerCase()===alvo.toLowerCase());
    if(found)return found;
  }
  return lista[0]||null;
}
function etqRender(){
  if(!etqCfg)return;
  const modelos=Array.isArray(etqCfg.modelos)?etqCfg.modelos:[];
  const sel=Number(etqCfg.selectedId||0)||0;
  etqCfg.tbody.innerHTML=modelos.map(item=>{
    const id=Number(item.id||0)||0;
    const nome=esc(item.nome||"");
    const arquivo=esc(item.nome_arquivo||"");
    const padrao=esc(item.padrao_nome||"Definido pelo usuário");
    const active=id===sel;
    return `<tr data-id="${id}" class="${active?"selected":""}"><td>${nome}</td><td>${arquivo}</td><td>${padrao}</td></tr>`;
  }).join("");
  const total=modelos.length;
  if(etqCfg.total)etqCfg.total.textContent=`${total} etiqueta${total===1?"":"s"}`;
}
function etqSyncPreview(){
  if(!etqCfg?.editPreview)return;
  const cols=Math.max(1,Math.min(10,parseInt(etqCfg.editColunas.value||"1",10)||1));
  const rows=Math.max(1,Math.min(40,parseInt(etqCfg.editLinhas.value||"1",10)||1));
  const margemEsq=etqNumero(etqCfg.editMargemEsq.value,0);
  const margemSup=etqNumero(etqCfg.editMargemSup.value,0);
  const gapH=etqNumero(etqCfg.editEspH.value,0);
  const gapV=etqNumero(etqCfg.editEspV.value,0);
  const padraoLabel=etqCfg.editPadrao?.selectedOptions?.[0]?.textContent||"";
  const isEnvelope=cols===1&&rows===1&&/envelope/i.test(padraoLabel);
  const pageW=210;
  const pageH=297;
  const frame=etqCfg.editPreview.parentElement;
  const maxW=frame?.clientWidth||300;
  const maxH=frame?.clientHeight||220;
  const scale=Math.min(maxW/pageW,maxH/pageH);
  const pagePxW=Math.max(120,Math.floor(pageW*scale));
  const pagePxH=Math.max(160,Math.floor(pageH*scale));
  etqCfg.editPreview.style.width=`${pagePxW}px`;
  etqCfg.editPreview.style.height=`${pagePxH}px`;
  etqCfg.editPreview.innerHTML="";
  let labelWmm,labelHmm;
  if(isEnvelope){
    labelWmm=90;
    labelHmm=50;
  }else{
    const margemDir=margemEsq;
    const margemInf=margemSup;
    const usableW=Math.max(10,pageW-margemEsq-margemDir-gapH*(cols-1));
    const usableH=Math.max(10,pageH-margemSup-margemInf-gapV*(rows-1));
    labelWmm=usableW/cols;
    labelHmm=usableH/rows;
  }
  const labelWpx=Math.max(6,labelWmm*scale);
  const labelHpx=Math.max(6,labelHmm*scale);
  const startX=Math.max(0,margemEsq*scale);
  const startY=Math.max(0,margemSup*scale);
  const gapX=gapH*scale;
  const gapY=gapV*scale;
  const total=Math.min(cols*rows,200);
  for(let i=0;i<total;i++){
    const r=Math.floor(i/cols);
    const c=i%cols;
    const x=startX+(labelWpx+gapX)*c;
    const y=startY+(labelHpx+gapY)*r;
    const box=document.createElement("div");
    box.className="etq-preview-box";
    box.style.left=`${x}px`;
    box.style.top=`${y}px`;
    box.style.width=`${labelWpx}px`;
    box.style.height=`${labelHpx}px`;
    etqCfg.editPreview.appendChild(box);
  }
}
function etqAplicarPadraoSelecionado(){
  if(!etqCfg)return;
  const padraoSel=etqCfg.editPadrao.value;
  const usarUser=padraoSel==="user";
  const padrao=Array.isArray(etqCfg.padroes)?etqCfg.padroes.find(p=>String(p.id)===padraoSel):null;
  const campos=[etqCfg.editMargemEsq,etqCfg.editMargemSup,etqCfg.editEspH,etqCfg.editEspV,etqCfg.editColunas,etqCfg.editLinhas];
  if(padrao&&!usarUser){
    etqCfg.editMargemEsq.value=etqFormatNumero(padrao.margem_esq);
    etqCfg.editMargemSup.value=etqFormatNumero(padrao.margem_sup);
    etqCfg.editEspH.value=etqFormatNumero(padrao.esp_horizontal);
    etqCfg.editEspV.value=etqFormatNumero(padrao.esp_vertical);
    etqCfg.editColunas.value=String(padrao.nro_colunas||1);
    etqCfg.editLinhas.value=String(padrao.nro_linhas||1);
  }
  campos.forEach(c=>{c.disabled=!usarUser});
  etqSyncPreview();
}
function etqLayoutFromItem(item){
  if(!item)return null;
  const cols=Math.max(1,Math.min(20,parseInt(item.nro_colunas||"1",10)||1));
  const rows=Math.max(1,Math.min(40,parseInt(item.nro_linhas||"1",10)||1));
  const margemEsq=etqNumero(item.margem_esq,0);
  const margemSup=etqNumero(item.margem_sup,0);
  const gapH=etqNumero(item.esp_horizontal,0);
  const gapV=etqNumero(item.esp_vertical,0);
  const padraoLabel=String(item.padrao_nome||item.nome||"");
  const isEnvelope=cols===1&&rows===1&&/envelope/i.test(padraoLabel);
  const pageW=210;
  const pageH=297;
  let labelWmm,labelHmm;
  if(isEnvelope){
    labelWmm=90;
    labelHmm=50;
  }else{
    const margemDir=margemEsq;
    const margemInf=margemSup;
    const usableW=Math.max(10,pageW-margemEsq-margemDir-gapH*(cols-1));
    const usableH=Math.max(10,pageH-margemSup-margemInf-gapV*(rows-1));
    labelWmm=usableW/cols;
    labelHmm=usableH/rows;
  }
  const labels=[];
  for(let r=0;r<rows;r++){
    for(let c=0;c<cols;c++){
      const x=margemEsq+(labelWmm+gapH)*c;
      const y=margemSup+(labelHmm+gapV)*r;
      labels.push({x,y,w:labelWmm,h:labelHmm});
    }
  }
  return {pageW,pageH,labels};
}
function etqTesteImprimir(){
  const item=etqSelecionado();
  if(!item){window.alert("Selecione um modelo.");return}
  const layout=etqLayoutFromItem(item);
  if(!layout){window.alert("Layout de etiqueta inválido.");return}
  const win=window.open("","_blank","width=900,height=700");
  if(!win){window.alert("Não foi possível abrir a janela de impressão.");return}
  const labelsHtml=layout.labels.map(l=>`<div class="label" style="left:${l.x}mm;top:${l.y}mm;width:${l.w}mm;height:${l.h}mm;"></div>`).join("");
  win.document.write(`<!doctype html><html><head><title>Teste de etiquetas</title><style>
  @page { size: A4; margin: 0; }
  html,body{margin:0;padding:0}
  body{background:#fff}
  .page{position:relative;width:${layout.pageW}mm;height:${layout.pageH}mm;margin:0 auto;box-sizing:border-box}
  .label{position:absolute;border:1px solid #000;border-radius:4px;box-sizing:border-box}
  </style></head><body><div class="page">${labelsHtml}</div></body></html>`);
  win.document.close();
  win.focus();
  setTimeout(()=>{win.print()},200);
}
function etqFixarPadraoUser(){
  if(!etqCfg)return;
  if(etqCfg.editPadrao.value!=="user"){
    etqCfg.editPadrao.value="user";
    etqAplicarPadraoSelecionado();
  }
}
function etqRenderCombos(){
  if(!etqCfg)return;
  const padroes=Array.isArray(etqCfg.padroes)?etqCfg.padroes:[];
  etqCfg.editPadrao.innerHTML=[
    ...padroes.map(p=>`<option value="${p.id}">${esc(p.nome||"")}</option>`),
    `<option value="user">Definido pelo usuário</option>`,
  ].join("");
  const arquivos=etqArquivosOrdenados();
  etqCfg.editArquivo.innerHTML=arquivos.map(a=>`<option value="${a.id}" data-arquivo="${esc(a.nome_arquivo||"")}">${esc(a.nome_arquivo||a.nome||"")}</option>`).join("");
}
function etqAbrirModal(modo){
  if(!etqCfg)return;
  const editar=modo==="editar";
  const item=editar?etqSelecionado():null;
  if(editar&&!item){window.alert("Selecione um modelo.");return}
  etqCfg.editMode=editar?"editar":"novo";
  etqCfg.editId=editar?Number(item.id||0)||0:null;
  if(etqCfg.editTitle)etqCfg.editTitle.textContent=editar?"Edita modelo de etiqueta":"Novo modelo de etiqueta";
  etqCfg.editNome.value=editar?String(item.nome||""): "";
  etqRenderCombos();
  let padraoId=editar?item.padrao_id:null;
  if(padraoId==null)etqCfg.editPadrao.value="user";else etqCfg.editPadrao.value=String(padraoId);
  const arquivoId=editar?item.modelo_documento_id:null;
  const arquivoOpt=arquivoId?etqCfg.editArquivo.querySelector(`option[value="${arquivoId}"]`):null;
  if(arquivoId&&arquivoOpt){etqCfg.editArquivo.value=String(arquivoId)}
  else{
    const padraoDefault=padraoId||Number(etqCfg.editPadrao.value||0)||0;
    const arquivoPadrao=etqResolverArquivoPadrao(padraoDefault);
    if(arquivoPadrao)etqCfg.editArquivo.value=String(arquivoPadrao.id);
  }
  if(editar){
    etqCfg.editMargemEsq.value=etqFormatNumero(item.margem_esq);
    etqCfg.editMargemSup.value=etqFormatNumero(item.margem_sup);
    etqCfg.editEspH.value=etqFormatNumero(item.esp_horizontal);
    etqCfg.editEspV.value=etqFormatNumero(item.esp_vertical);
    etqCfg.editColunas.value=String(item.nro_colunas||1);
    etqCfg.editLinhas.value=String(item.nro_linhas||1);
  }
  etqAplicarPadraoSelecionado();
  etqSyncPreview();
  etqCfg.editBackdrop.classList.remove("hidden");
}
function etqFecharModal(){if(etqCfg?.editBackdrop)etqCfg.editBackdrop.classList.add("hidden")}
async function etqSalvarModal(){
  if(!etqCfg)return;
  const nome=String(etqCfg.editNome.value||"").trim();
  if(!nome){window.alert("Informe o nome do modelo.");return}
  const padraoRaw=etqCfg.editPadrao.value;
  const padraoId=padraoRaw==="user"?null:Number(padraoRaw||0)||null;
  const arquivoId=Number(etqCfg.editArquivo.value||0)||null;
  if(!arquivoId){window.alert("Selecione o arquivo de modelo.");return}
  const payload={
    nome,
    padrao_id:padraoId,
    modelo_documento_id:arquivoId,
    margem_esq:etqNumero(etqCfg.editMargemEsq.value,null),
    margem_sup:etqNumero(etqCfg.editMargemSup.value,null),
    esp_horizontal:etqNumero(etqCfg.editEspH.value,null),
    esp_vertical:etqNumero(etqCfg.editEspV.value,null),
    nro_colunas:etqNumero(etqCfg.editColunas.value,null),
    nro_linhas:etqNumero(etqCfg.editLinhas.value,null),
  };
  try{
    const editando=etqCfg.editMode==="editar";
    const path=editando?`/config/etiquetas/modelos/${etqCfg.editId}`:"/config/etiquetas/modelos";
    const method=editando?"PUT":"POST";
    const {res,data}=await requestJson(method,path,payload,true);
    if(!res.ok)throw new Error(data.detail||"Falha ao salvar modelo.");
    const modelo=data.modelo||null;
    if(modelo){
      if(editando){
        etqCfg.modelos=etqCfg.modelos.map(item=>Number(item.id)===Number(modelo.id)?modelo:item);
      }else{
        etqCfg.modelos=[...etqCfg.modelos,modelo].sort((a,b)=>String(a.nome||"").localeCompare(String(b.nome||""),"pt-BR"));
      }
    }else{
      await etqCarregarDados();
    }
    etqCfg.selectedId=modelo?modelo.id:etqCfg.selectedId;
    etqRender();
    etqFecharModal();
    footerMsg.textContent=data.detail||"Modelo atualizado.";
  }catch(err){
    window.alert(err?.message||"Falha ao salvar modelo.");
  }
}
async function etqExcluirSelecionado(){
  if(!etqCfg)return;
  const item=etqSelecionado();
  if(!item){window.alert("Selecione um modelo.");return}
  if(item.reservado){window.alert("Modelo reservado do sistema.");return}
  if(!window.confirm(`Eliminar o modelo "${item.nome||""}"?`))return;
  try{
    const {res,data}=await requestJson("DELETE",`/config/etiquetas/modelos/${item.id}`,undefined,true);
    if(!res.ok)throw new Error(data.detail||"Falha ao eliminar modelo.");
    etqCfg.modelos=etqCfg.modelos.filter(m=>Number(m.id)!==Number(item.id));
    etqCfg.selectedId=etqCfg.modelos[0]?.id||null;
    etqRender();
    footerMsg.textContent=data.detail||"Modelo eliminado.";
  }catch(err){
    window.alert(err?.message||"Falha ao eliminar modelo.");
  }
}
async function etqCarregarDados(){
  const {res:resP,data:dataP}=await requestJson("GET","/config/etiquetas/padroes",undefined,true);
  if(!resP.ok)throw new Error(dataP.detail||"Falha ao carregar padrões.");
  const {res:resA,data:dataA}=await requestJson("GET","/config/etiquetas/arquivos",undefined,true);
  if(!resA.ok)throw new Error(dataA.detail||"Falha ao carregar arquivos.");
  const {res:resM,data:dataM}=await requestJson("GET","/config/etiquetas/modelos",undefined,true);
  if(!resM.ok)throw new Error(dataM.detail||"Falha ao carregar modelos.");
  etqCfg.padroes=Array.isArray(dataP.padroes)?dataP.padroes:[];
  etqCfg.arquivos=Array.isArray(dataA.arquivos)?dataA.arquivos:[];
  etqCfg.modelos=Array.isArray(dataM.modelos)?dataM.modelos:[];
}
