  el.style.fontFamily=String(style.fonte_nome||"Tahoma");
  el.style.fontSize=`${Number(style.fonte_tamanho||12)}px`;
  el.style.color=String(style.cor_texto||"#000000");
  el.style.fontWeight=estilo==="negrito"||estilo==="negrito-italico"?"700":"400";
  el.style.fontStyle=estilo==="italico"||estilo==="negrito-italico"?"italic":"normal";
