const PREF_ODONTO_PALETTE=[
  {value:"#000000",label:"Preto"},
  {value:"#800000",label:"Bordo"},
  {value:"#008000",label:"Verde"},
  {value:"#808000",label:"Verde-oliva"},
  {value:"#000080",label:"Azul-marinho"},
  {value:"#800080",label:"Roxo"},
  {value:"#008080",label:"Azul-petroleo"},
  {value:"#808080",label:"Cinza"},
  {value:"#c0c0c0",label:"Prateado"},
  {value:"#ff0000",label:"Vermelho"},
  {value:"#00ff00",label:"Verde-limao"},
  {value:"#ffff00",label:"Amarelo"},
  {value:"#0000ff",label:"Azul"},
  {value:"#ff00ff",label:"Fucsia"},
  {value:"#00ffff",label:"Azul-piscina"},
  {value:"#ffffff",label:"Branco"},
];
const PREF_ODONTO_PALETTE_BY_VALUE=(()=>{const map={};PREF_ODONTO_PALETTE.forEach(item=>{map[String(item.value).toLowerCase()]=item});return map})();
function prefOdontoNorm(text){return String(text||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase().trim()}
function prefOdontoFindByLabel(text){const key=prefOdontoNorm(text);for(let i=0;i<PREF_ODONTO_PALETTE.length;i+=1){if(prefOdontoNorm(PREF_ODONTO_PALETTE[i].label)===key)return PREF_ODONTO_PALETTE[i]}return null}
function prefOdontoEnsurePalette(select){
  if(!(select instanceof HTMLSelectElement))return;
  const currentValue=String(select.value||"").trim().toLowerCase();
  const currentLabel=select.selectedOptions&&select.selectedOptions[0]?String(select.selectedOptions[0].textContent||""):"";
  if(!select.dataset.palette){
    select.innerHTML=PREF_ODONTO_PALETTE.map(item=>`<option value="${item.value}">${item.label}</option>`).join("");
    select.dataset.palette="1";
  }
  const chosen=PREF_ODONTO_PALETTE_BY_VALUE[currentValue]||prefOdontoFindByLabel(currentLabel)||PREF_ODONTO_PALETTE[0];
  select.value=chosen.value;
}
function prefOdontoCloseLists(except){
  document.querySelectorAll(".pref-odonto-color-list").forEach(list=>{
    if(except&&list===except)return;
    list.classList.add("pref-odonto-color-hidden");
  });
}
function prefOdontoSyncHeader(select,root){
  if(!(select instanceof HTMLSelectElement)||!(root instanceof HTMLElement))return;
  const opt=select.selectedOptions&&select.selectedOptions[0]?select.selectedOptions[0]:null;
  const item=opt?PREF_ODONTO_PALETTE_BY_VALUE[String(opt.value||"").toLowerCase()]||prefOdontoFindByLabel(opt.textContent):null;
  const sw=root.querySelector(".pref-odonto-color-swatch");
  const lb=root.querySelector(".pref-odonto-color-label");
  if(sw instanceof HTMLElement)sw.style.background=item?item.value:"#000000";
  if(lb instanceof HTMLElement)lb.textContent=item?item.label:String(opt?opt.textContent:"");
}
function prefOdontoRenderList(select,root){
  if(!(select instanceof HTMLSelectElement)||!(root instanceof HTMLElement))return;
  const list=root.querySelector(".pref-odonto-color-list");
  if(!(list instanceof HTMLDivElement))return;
  list.innerHTML="";
  PREF_ODONTO_PALETTE.forEach(item=>{
    const row=document.createElement("div");
    const isActive=String(select.value||"").toLowerCase()===String(item.value).toLowerCase();
    row.className="pref-odonto-color-item"+(isActive?" active":"");
    row.innerHTML=`<span class="pref-odonto-color-swatch" style="background:${item.value}"></span><span class="pref-odonto-color-label">${item.label}</span>`;
    row.addEventListener("click",()=>{
      select.value=item.value;
      select.dispatchEvent(new Event("change",{bubbles:true}));
      prefOdontoSyncHeader(select,root);
      prefOdontoRenderList(select,root);
      prefOdontoCloseLists();
    });
    list.appendChild(row);
  });
}
function prefOdontoEnsureDropdown(select){
  if(!(select instanceof HTMLSelectElement))return;
  const wrap=select.parentElement;
  if(!(wrap instanceof HTMLElement))return;
  let dropdown=wrap.querySelector(".pref-odonto-color-dropdown");
  if(!(dropdown instanceof HTMLElement)){
    dropdown=document.createElement("div");
    dropdown.className="pref-odonto-color-dropdown";
    dropdown.innerHTML='<button type="button" class="pref-odonto-color-btn"><span class="pref-odonto-color-swatch"></span><span class="pref-odonto-color-label"></span><span>▼</span></button><div class="pref-odonto-color-list pref-odonto-color-hidden"></div>';
    wrap.appendChild(dropdown);
    const btn=dropdown.querySelector(".pref-odonto-color-btn");
    const list=dropdown.querySelector(".pref-odonto-color-list");
    if(btn instanceof HTMLButtonElement && list instanceof HTMLDivElement){
      btn.addEventListener("click",(ev)=>{
        ev.stopPropagation();
        const willOpen=list.classList.contains("pref-odonto-color-hidden");
        prefOdontoCloseLists(willOpen?list:null);
        list.classList.toggle("pref-odonto-color-hidden",!willOpen);
      });
    }
    select.addEventListener("change",()=>{
      prefOdontoSyncHeader(select,dropdown);
      prefOdontoRenderList(select,dropdown);
    });
  }
  select.classList.add("pref-odonto-color-native-hidden");
  prefOdontoSyncHeader(select,dropdown);
  prefOdontoRenderList(select,dropdown);
}
function prefOdontoEnsureColorDropdowns(){
  if(!prefCfg)return;
  const selects=[prefCfg.corOdontoAnomalia,prefCfg.corOdontoObservada,prefCfg.corOdontoRealizado,prefCfg.corOdontoRealizar].filter(Boolean);
  selects.forEach(sel=>{prefOdontoEnsurePalette(sel);prefOdontoEnsureDropdown(sel);});
  if(!prefCfg._odontoColorCloseBound){
    document.addEventListener("click",()=>prefOdontoCloseLists());
    prefCfg._odontoColorCloseBound=true;
  }
}
