  if(prefCfg.cboModeloRecibo.value!==String(sm.modelo_impresso_recibos_id==null?"":sm.modelo_impresso_recibos_id)&&prefCfg.cboModeloRecibo.options.length)prefCfg.cboModeloRecibo.value=String(prefCfg.cboModeloRecibo.options[0]?.value||"");
  prefCfg.cboModeloEtiqueta.value=sm.modelo_padrao_etiquetas_id==null?"":String(sm.modelo_padrao_etiquetas_id);
