async function prefCarregarDados(){if(!prefCfg)return false;const ctx=prefContextoAtual();const qs=ctx.userId?`?user_id=${encodeURIComponent(ctx.userId)}`:"";const geralResp=await requestJson("GET",`/preferences/general${qs}`,undefined,true);if(!geralResp.res.ok){window.alert(geralResp.data.detail||"Falha ao carregar preferencias.");return false}prefCfg.targetUser=geralResp.data?.user||{};prefCfg.geralOptions=geralResp.data?.options||{};prefCfg.geralValues=geralResp.data?.values||prefValoresPadrao();const modelosResp=await requestJson("GET",`/preferences/models${qs}`,undefined,true);if(modelosResp.res.ok){prefCfg.targetUser=modelosResp.data?.user||prefCfg.targetUser;prefCfg.modelosOptions=modelosResp.data?.options||{};prefCfg.modelosValues=modelosResp.data?.values||prefValoresPadraoModelos()}else{prefCfg.modelosOptions={};prefCfg.modelosValues=prefValoresPadraoModelos();footerMsg.textContent=modelosResp.data?.detail||"Nao foi possivel carregar a aba Modelos."}const ambienteResp=await requestJson("GET",`/preferences/environment${qs}`,undefined,true);if(ambienteResp.res.ok){prefCfg.targetUser=ambienteResp.data?.user||prefCfg.targetUser;prefCfg.ambienteOptions=ambienteResp.data?.options||{};prefCfg.ambienteValues=ambienteResp.data?.values||prefValoresPadraoAmbiente()}else{prefCfg.ambienteOptions={};prefCfg.ambienteValues=prefValoresPadraoAmbiente()}const dadosResp=await requestJson("GET",`/preferences/user-data${qs}`,undefined,true);if(dadosResp.res.ok){prefCfg.targetUser=dadosResp.data?.user||prefCfg.targetUser;prefCfg.dadosValues=dadosResp.data?.values||prefValoresPadraoDados()}else{prefCfg.dadosValues=prefValoresPadraoDados()}const odontoResp=await requestJson("GET",`/preferences/odontogram${qs}`,undefined,true);if(odontoResp.res.ok){prefCfg.targetUser=odontoResp.data?.user||prefCfg.targetUser;prefCfg.odontogramaOptions=odontoResp.data?.options||{};prefCfg.odontogramaValues=odontoResp.data?.values||prefValoresPadraoOdontograma();prefCfg.odontogramaHint=String(odontoResp.data?.integration_hint||"").trim()}else{prefCfg.odontogramaOptions={};prefCfg.odontogramaValues=prefValoresPadraoOdontograma();prefCfg.odontogramaHint=""}prefSincronizarUI();if(prefCfg.lblOdontoHint)prefCfg.lblOdontoHint.textContent=prefCfg.odontogramaHint||"Estas preferencias ja estao prontas para o futuro modulo Odontograma.";return true}
