function pgenRender(){
  pgen.tbody.innerHTML=pgenCache.map(item=>`<tr data-id="${item.id}" class="${item.id===pgenSelId?"selected":""}"><td>${esc(item.codigo||"")}</td><td>${esc(item.descricao||"")}</td><td>${esc(pgenEspecialidadeNome(item.especialidade||""))}</td><td>${pgenStatusDot(item.inativo)}</td></tr>`).join("");
  pgen.lblTotal.textContent=`${pgenCache.length} procedimentos`;
}
function pgenFasesSelecionar(idx){
  pgenFasesSelecionadaIdx=idx;
  if(!pgen?.fasesListTbody)return;
  pgen.fasesListTbody.querySelectorAll("tr[data-idx]").forEach(tr=>tr.classList.toggle("selected",Number(tr.dataset.idx||-1)===idx));
}
function pgenFasesRender(){
  if(!pgen?.fasesListTbody)return;
  const fases=Array.isArray(pgenFasesState?.fases)?pgenFasesState.fases:[];
  pgen.fasesListTbody.innerHTML=fases.map((item,idx)=>`<tr data-idx="${idx}" class="${idx===pgenFasesSelecionadaIdx?"selected":""}"><td>${Number(item.sequencia||idx+1)}</td><td>${esc(String(item.codigo||""))}</td><td>${esc(String(item.descricao||""))}</td><td>${Number(item.tempo||0)}</td></tr>`).join("")||'<tr><td colspan="4"></td></tr>';
  pgen.fasesTotal.textContent=`${fases.length} fases`;
}
function pgenFasesFechar(){
  if(pgen?.fasesBackdrop)pgen.fasesBackdrop.classList.add("hidden");
  pgenFasesState=null;
  pgenFasesSelecionadaIdx=-1;
  pgenFaseEditFechar();
}
function pgenFaseEditFechar(){
  if(pgen?.faseEditBackdrop)pgen.faseEditBackdrop.classList.add("hidden");
  pgenFaseEditIdx=null;
}
async function pgenAbrirFases(){
  const item=pgenSelecionado();
  if(!item){window.alert("Selecione um procedimento genérico.");return}
  const {res,data}=await requestJson("GET",`/cadastros/procedimentos-genericos/detalhe/${item.id}`,undefined,true);
  if(!res.ok){window.alert(data.detail||"Falha ao carregar as fases do procedimento.");return}
  pgenFasesState=pgenDetalheParaEstado(data);
  pgenFasesSelecionadaIdx=(pgenFasesState.fases||[]).length?0:-1;
  pgenCorrigirRotulos();
  pgenFasesRender();
  pgen.fasesBackdrop.classList.remove("hidden");
}
async function pgenFaseEditAbrir(idx=null){
  if(!pgenFasesState){await pgenAbrirFases();if(!pgenFasesState)return}
  const fasesAux=await pgenCarregarAuxFases();
  procPreencherSelect(pgen.faseSelect,fasesAux,{valueFrom:item=>item?.codigo??"",labelFrom:item=>item?.nome??item?.descricao??item?.codigo??""});
  const faseAtual=(idx!=null&&idx>=0)?(pgenFasesState.fases||[])[idx]:null;
  pgenFaseEditIdx=faseAtual?idx:null;
  pgen.faseEditTitle.textContent=faseAtual?"Altera fase":"Nova fase";
  if(faseAtual){
    procGarantirOpcaoSelect(pgen.faseSelect,faseAtual.codigo,faseAtual.descricao||faseAtual.codigo);
    pgen.faseSelect.value=String(faseAtual.codigo||"");
    pgen.faseTempo.value=String(Number(faseAtual.tempo||0));
  }else{
    pgen.faseSelect.value=String(fasesAux[0]?.codigo||"");
    pgen.faseTempo.value="0";
  }
  pgen.faseEditBackdrop.classList.remove("hidden");
}
async function pgenFaseEditSalvar(){
  if(!pgenFasesState)return;
  const codigo=String(pgen.faseSelect.value||"").trim();
  if(!codigo){window.alert("Selecione a fase do procedimento.");return}
  const fasesAux=Array.isArray(pgenFasesAuxCache)?pgenFasesAuxCache:[];
  const faseAux=fasesAux.find(item=>String(item.codigo||"").trim()===codigo)||null;
  const descricao=String(faseAux?.nome||faseAux?.descricao||codigo).trim();
  const tempo=Math.max(0,Number(pgen.faseTempo.value||0));
  const fases=Array.isArray(pgenFasesState.fases)?[...pgenFasesState.fases]:[];
  const duplicada=fases.some((item,idx)=>String(item.codigo||"").trim()===codigo&&idx!==pgenFaseEditIdx);
  if(duplicada){window.alert("Esta fase já está vinculada ao procedimento.");return}
  const novaFase={codigo,descricao,tempo,sequencia:1};
  if(pgenFaseEditIdx!=null&&pgenFaseEditIdx>=0&&pgenFaseEditIdx<fases.length){
    fases[pgenFaseEditIdx]={...fases[pgenFaseEditIdx],...novaFase};
  }else{
    fases.push(novaFase);
  }
  pgenFasesState.fases=fases.map((item,idx)=>({...item,sequencia:idx+1}));
  try{
    const salvo=await pgenPersistirFases(pgenFasesState);
    pgenFasesState=pgenDetalheParaEstado(salvo);
    pgenFasesSelecionadaIdx=pgenFaseEditIdx!=null&&pgenFaseEditIdx>=0?Math.min(pgenFaseEditIdx,pgenFasesState.fases.length-1):Math.max(0,pgenFasesState.fases.length-1);
    pgenFaseEditFechar();
    pgenFasesRender();
    await pgenCarregar();
    if(pgenFasesState?.id)pgenSelecionar(pgenFasesState.id);
    if(pgenEditorId&&pgenEditorState&&Number(pgenEditorId)===Number(pgenFasesState.id||0)){
      pgenEditorState.fases=[...(pgenFasesState.fases||[])];
      pgenCalcularCustos();
    }
  }catch(err){
    window.alert(err?.message||"Falha ao gravar a fase.");
  }
}
async function pgenFaseExcluirSelecionada(){
  if(!pgenFasesState){window.alert("Selecione um procedimento genérico.");return}
  if(!(pgenFasesSelecionadaIdx>=0)){window.alert("Selecione uma fase.");return}
  const fase=(pgenFasesState.fases||[])[pgenFasesSelecionadaIdx];
  if(!fase)return;
  if(!window.confirm(`Confirma a eliminação da fase ${fase.descricao}?`))return;
  pgenFasesState.fases=(pgenFasesState.fases||[]).filter((_,idx)=>idx!==pgenFasesSelecionadaIdx).map((item,idx)=>({...item,sequencia:idx+1}));
  try{
    const salvo=await pgenPersistirFases(pgenFasesState);
    pgenFasesState=pgenDetalheParaEstado(salvo);
    pgenFasesSelecionadaIdx=(pgenFasesState.fases||[]).length?Math.min(pgenFasesSelecionadaIdx,pgenFasesState.fases.length-1):-1;
    pgenFasesRender();
    await pgenCarregar();
    if(pgenFasesState?.id)pgenSelecionar(pgenFasesState.id);
    if(pgenEditorId&&pgenEditorState&&Number(pgenEditorId)===Number(pgenFasesState.id||0)){
      pgenEditorState.fases=[...(pgenFasesState.fases||[])];
      pgenCalcularCustos();
    }
  }catch(err){
    window.alert(err?.message||"Falha ao excluir a fase.");
  }
}
function pgenMateriaisSelecionar(idx){
  pgenMaterialSelecionadoIdx=idx;
  if(!pgen?.matsListTbody)return;
  pgen.matsListTbody.querySelectorAll("tr[data-idx]").forEach(tr=>tr.classList.toggle("selected",Number(tr.dataset.idx||-1)===idx));
}
function pgenMateriaisRender(){
  if(!pgen?.matsListTbody)return;
  const itens=Array.isArray(pgenEditorState?.materiais)?pgenEditorState.materiais:[];
  pgen.matsListTbody.innerHTML=itens.map((item,idx)=>`<tr data-idx="${idx}" class="${idx===pgenMaterialSelecionadoIdx?"selected":""}"><td>${esc(String(item.nome||""))}</td><td>/</td><td>${formatNum(Number(item.quantidade||0))}</td><td>${formatMoney(Number(item.custo_und||0)*Number(item.quantidade||0))}</td></tr>`).join("")||'<tr><td colspan="4"></td></tr>';
  pgen.matsTotal.textContent=`${itens.length} materiais`;
}
function pgenMateriaisFechar(){
  if(pgen?.matsBackdrop)pgen.matsBackdrop.classList.add("hidden");
  pgenMaterialSelecionadoIdx=-1;
  pgenMaterialEditFechar();
}
async function pgenCarregarListasMateriais(){
  const {res,data}=await requestJson("GET","/materiais/listas",undefined,true);
  if(!res.ok)return [];
  return Array.isArray(data)?data:[];
}
async function pgenBuscarMateriais(){
  if(!pgen)return;
  const listaId=Number(pgen.matLista?.value||0);
  if(!listaId){
    pgenEditorBuscaMateriais=[];
    if(pgen.matSelect)pgen.matSelect.innerHTML="";
    pgenAtualizarCustoMaterialEditor();
    return;
  }
  const q=encodeURIComponent(String(pgen.matQ?.value||"").trim());
  const {res,data}=await requestJson("GET",`/materiais?lista_id=${listaId}&q=${q}&classificacao=__todos__`,undefined,true);
  pgenEditorBuscaMateriais=res&&Array.isArray(data)?data:[];
  if(pgen.matSelect){
    pgen.matSelect.innerHTML=pgenEditorBuscaMateriais.map(item=>`<option value="${item.id}">${esc(item.nome||"")}</option>`).join("");
  }
  pgenAtualizarCustoMaterialEditor();
}
function pgenAtualizarCustoMaterialEditor(){
  if(!pgen)return;
  const item=pgenEditorBuscaMateriais.find(x=>Number(x.id||0)===Number(pgen.matSelect?.value||0));
  const qtd=Math.max(0,Number(pgen.matQuantidade?.value||0));
  const custoUnit=Number(item?.custo||0);
  const total=item?(Number(item.custo||0)*qtd):0;
  if(pgen.matCustoUnit)pgen.matCustoUnit.value=procFmtBr(custoUnit);
  if(pgen.matCustoTotal)pgen.matCustoTotal.value=procFmtBr(total);
}
async function pgenAbrirMateriais(){
  const item=pgenSelecionado();
  if(!item){window.alert("Selecione um procedimento genérico.");return}
  const {res,data}=await requestJson("GET",`/cadastros/procedimentos-genericos/detalhe/${item.id}`,undefined,true);
  if(!res.ok){window.alert(data.detail||"Falha ao carregar os materiais do procedimento.");return}
  pgenEditorState=pgenDetalheParaEstado(data);
  pgenMaterialSelecionadoIdx=(pgenEditorState.materiais||[]).length?0:-1;
  pgenCorrigirRotulos();
  pgenMateriaisRender();
  pgen.matsBackdrop.classList.remove("hidden");
}
async function pgenMaterialEditAbrir(idx=null){
  if(!pgenEditorState){await pgenAbrirMateriais();if(!pgenEditorState)return}
  const listas=await pgenCarregarListasMateriais();
  procPreencherSelect(pgen.matLista,listas,{valueFrom:item=>item?.id??"",labelFrom:item=>item?.nome??""});
  if(!pgen.matLista.value&&listas[0]?.id)pgen.matLista.value=String(listas[0].id);
  pgenMaterialEditIdx=(idx!=null&&idx>=0)?idx:null;
  pgen.matEditTitle.textContent=pgenMaterialEditIdx!=null?"Altera material de procedimento":"Novo material de procedimento";
  pgen.matQ.value="";
  await pgenBuscarMateriais();
  const materialAtual=pgenMaterialEditIdx!=null?(pgenEditorState.materiais||[])[pgenMaterialEditIdx]:null;
  if(materialAtual){
    procGarantirOpcaoSelect(pgen.matSelect,String(materialAtual.material_id||""),`${materialAtual.nome||""}`);
    pgen.matSelect.value=String(materialAtual.material_id||"");
    pgen.matQuantidade.value=String(Number(materialAtual.quantidade||0));
    pgenAtualizarCustoMaterialEditor();
  }else{
    pgen.matQuantidade.value="0";
    pgenAtualizarCustoMaterialEditor();
  }
  pgen.matEditBackdrop.classList.remove("hidden");
}
function pgenMaterialEditFechar(){
  if(pgen?.matEditBackdrop)pgen.matEditBackdrop.classList.add("hidden");
  pgenMaterialEditIdx=null;
}
async function pgenMaterialEditSalvar(){
  if(!pgenEditorState)return;
  const item=pgenEditorBuscaMateriais.find(x=>Number(x.id||0)===Number(pgen.matSelect?.value||0));
  if(!item){window.alert("Selecione um material.");return}
  const quantidade=Math.max(0,Number(pgen.matQuantidade?.value||0));
  if(!(quantidade>0)){window.alert("Informe uma quantidade válida.");return}
  const materiais=Array.isArray(pgenEditorState.materiais)?[...pgenEditorState.materiais]:[];
  const novo={material_id:Number(item.id||0),codigo:String(item.codigo||""),nome:String(item.nome||""),quantidade,custo_und:Number(item.custo||0)};
  const duplicada=materiais.some((x,idx)=>Number(x.material_id||0)===novo.material_id&&idx!==pgenMaterialEditIdx);
  if(duplicada){window.alert("Este material já está vinculado ao procedimento.");return}
  if(pgenMaterialEditIdx!=null&&pgenMaterialEditIdx>=0&&pgenMaterialEditIdx<materiais.length)materiais[pgenMaterialEditIdx]={...materiais[pgenMaterialEditIdx],...novo};
  else materiais.push(novo);
  pgenEditorState.materiais=materiais;
  try{
    const salvo=await pgenPersistirMateriais(pgenEditorState);
    pgenEditorState=pgenDetalheParaEstado(salvo);
    pgenMaterialSelecionadoIdx=pgenMaterialEditIdx!=null?Math.min(pgenMaterialEditIdx,pgenEditorState.materiais.length-1):Math.max(0,pgenEditorState.materiais.length-1);
    pgenMaterialEditFechar();
    pgenMateriaisRender();
    pgenCalcularCustos();
    await pgenCarregar();
    if(pgenEditorState?.id)pgenSelecionar(pgenEditorState.id);
  }catch(err){
    window.alert(err?.message||"Falha ao gravar o material.");
  }
}
function pgenMaterialExcluirSelecionado(){
  if(!(pgenMaterialSelecionadoIdx>=0)){window.alert("Selecione um material.");return}
  const item=(pgenEditorState?.materiais||[])[pgenMaterialSelecionadoIdx];
  if(!item)return;
  if(!window.confirm(`Confirma a eliminação do material ${item.nome}?`))return;
  pgenEditorState.materiais=(pgenEditorState.materiais||[]).filter((_,idx)=>idx!==pgenMaterialSelecionadoIdx);
  pgenPersistirMateriais(pgenEditorState).then(salvo=>{
    pgenEditorState=pgenDetalheParaEstado(salvo);
    pgenMaterialSelecionadoIdx=(pgenEditorState.materiais||[]).length?Math.min(pgenMaterialSelecionadoIdx,pgenEditorState.materiais.length-1):-1;
    pgenMateriaisRender();
    pgenCalcularCustos();
    return pgenCarregar().then(()=>{if(pgenEditorState?.id)pgenSelecionar(pgenEditorState.id)});
  }).catch(err=>{
    window.alert(err?.message||"Falha ao excluir o material.");
  });
}
async function pgenCarregar(){
  if(!pgen)return;
  const keep=pgenSelId;
  const q=encodeURIComponent((pgen.txtPesquisar.value||"").trim());
  const especialidade=encodeURIComponent(String(pgen.cboEspecialidade?.value||"").trim());
  const {res,data}=await requestJson("GET",`/cadastros/procedimentos-genericos?q=${q}&especialidade=${especialidade}`,undefined,true);
  if(!res.ok){footerMsg.textContent=data.detail||"Falha ao carregar procedimentos genéricos.";return}
  pgenCache=Array.isArray(data)?data:[];
  pgenSelId=pgenCache.some(item=>item.id===keep)?keep:(pgenCache[0]?.id||null);
  pgenRender();
  if(pgenSelId)pgenSelecionar(pgenSelId);
}
async function pgenAbrirEditor(id=null){
  if(!pgen)return;
  pgenEditorId=id?Number(id):null;
  await Promise.all([procCarregarCenario(),pgenCarregarEspecialidades()]);
  const [simbolos] = await Promise.all([pgenCarregarSimbolos()]);
procPreencherSelect(pgen.editorSimbolo,simbolos,{valueFrom:item=>item?.codigo??"",labelFrom:item=>procFmtSimboloLabel(item)});
  pgenPreencherEspecialidades();
  if(id){
    const {res,data}=await requestJson("GET",`/cadastros/procedimentos-genericos/detalhe/${id}`,undefined,true);
    if(!res.ok){window.alert(data.detail||"Falha ao carregar procedimento genérico.");return}
    pgenEditorState=pgenDetalheParaEstado(data);
  }else{
    const {res,data}=await requestJson("GET","/cadastros/procedimentos-genericos/proximo-codigo",undefined,true);
    pgenEditorState={...pgenEstadoVazio(res?String(data.codigo||""):""),especialidade:"",tempo:0,custo_lab:0,peso:0,inativo:false,data_inclusao:"",data_alteracao:"",vinculos:[]};
  }
  pgenEnsureTabData();
  pgen.editorTitle.textContent=pgenEditorId?"Altera procedimento":"Novo procedimento";
  pgen.editorCodigo.value=String(pgenEditorState.codigo||"");
  pgen.editorDescricao.value=String(pgenEditorState.descricao||"");
  pgen.editorEspecialidade.value=String(pgenEditorState.especialidade||"");
  pgen.editorPeso.value=String(pgenEditorState.peso||0);
  pgen.cdTempoInput.value=String(pgenEditorState.tempo||0);
  pgen.cdProteticoInput.value=procFmtBr(pgenEditorState.custo_lab||0);
  if(pgenEditorState.simbolo_grafico){
    procGarantirOpcaoSelect(pgen.editorSimbolo,pgenEditorState.simbolo_grafico,pgenSimboloDescricao(pgenEditorState.simbolo_grafico));
  }
  pgen.editorSimbolo.value=String(pgenEditorState.simbolo_grafico||"");
  pgen.editorInativo.checked=!!pgenEditorState.inativo;
  pgen.editorObs.value=String(pgenEditorState.observacoes||"");
  pgen.editorInclusao.textContent=String(pgenEditorState.data_inclusao||"");
  pgen.editorAlteracao.textContent=String(pgenEditorState.data_alteracao||"");
  pgenCorrigirRotulos();
  pgenAtualizarPreviewSimbolo();
  pgenCalcularCustos();
  pgenRenderVinculos();
  pgenSetTab("principal");
  pgen.editorBackdrop.classList.remove("hidden");
  pgenPosicionarEditorCentralizado();
}
async function pgenSalvarEditor(){
  if(!pgenEditorState)return;
  pgenEditorState.tempo=Math.max(0,Number(pgen.cdTempoInput.value||0));
  pgenEditorState.custo_lab=Math.max(0,Number(procParse(pgen.cdProteticoInput.value||"0")||0));
  const payload={codigo:(pgen.editorCodigo.value||"").trim(),descricao:(pgen.editorDescricao.value||"").trim(),especialidade:String(pgen.editorEspecialidade.value||"").trim(),tempo:pgenEditorState.tempo,custo_lab:pgenEditorState.custo_lab,peso:Number(pgen.editorPeso.value||0),simbolo_grafico:String(pgen.editorSimbolo.value||"").trim(),mostrar_simbolo:!!String(pgen.editorSimbolo.value||"").trim(),inativo:!!pgen.editorInativo.checked,observacoes:String(pgen.editorObs.value||"").trim(),fases:(pgenEditorState.fases||[]).map((x,idx)=>({codigo:String(x.codigo||"").trim(),descricao:String(x.descricao||"").trim(),sequencia:idx+1,tempo:Number(x.tempo||0)})).filter(x=>x.descricao),materiais:(pgenEditorState.materiais||[]).map(x=>({material_id:Number(x.material_id||0),quantidade:Number(x.quantidade||0)})).filter(x=>x.material_id>0&&x.quantidade>0)};
  if(!payload.codigo||!payload.descricao){window.alert("Informe código e descrição.");return}
  const method=pgenEditorId?"PUT":"POST";
  const path=pgenEditorId?`/cadastros/procedimentos-genericos/${pgenEditorId}`:"/cadastros/procedimentos-genericos";
  const {res,data}=await requestJson(method,path,payload,true);
  if(!res.ok){window.alert(data.detail||"Falha ao gravar procedimento genérico.");return}
  pgenFecharEditor();
  await pgenCarregar();
  pgenSelecionar(Number(data.id||pgenEditorId||0));
}
async function pgenExcluirSelecionado(){
  const item=pgenSelecionado();
  if(!item){window.alert("Selecione um procedimento genérico.");return}
  if(!window.confirm(`Confirma a eliminação do procedimento ${item.descricao}?`))return;
  const {res,data}=await requestJson("DELETE",`/cadastros/procedimentos-genericos/${item.id}`,undefined,true);
  if(!res.ok){window.alert(data.detail||"Falha ao excluir procedimento genérico.");return}
  await pgenCarregar();
}
async function pgenAbrir(){
  pgenEnsureUI();
  await pgenCarregarEspecialidades();
  const especialidades=Array.isArray(procFiltros?.especialidades)?procFiltros.especialidades:[];
  pgen.cboEspecialidade.innerHTML=['<option value="">&lt;&lt;Todas&gt;&gt;</option>',...especialidades.map(item=>`<option value="${esc(String(item.codigo||""))}">${esc(String(item.nome||""))}</option>`)].join("");
  pgenCorrigirRotulos();
  hideAllPanels();
  pgen.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
  await pgenCarregar();
  footerMsg.textContent="Módulo Procedimentos genéricos aberto.";
}
pgenCorrigirRotulos=function(){
  if(!pgen)return;
  const titulo=pgen.panel?.querySelector(".pgen-title");
  if(titulo)titulo.textContent="Cadastro de procedimentos gen\u00e9ricos";
  const heads=[...pgen.panel.querySelectorAll(".pgen-head span")];
  ["C\u00f3digo","Procedimento","Especialidade","Status"].forEach((texto,idx)=>{if(heads[idx])heads[idx].textContent=texto});
  const filtros=[["pgen-cbo-especialidade","Especialidade:"],["pgen-txt-pesquisar","Procedimento:"]];
  filtros.forEach(([id,texto])=>{
    const label=document.querySelector(`label[for='${id}']`);
    if(label)label.textContent=texto;
  });
  if(pgen.editorTitle)pgen.editorTitle.textContent=pgenEditorId?"Altera procedimento":"Novo procedimento";
  const abas=[
    ["pgen-tab-principal","Principal"],
    ["pgen-tab-custos","Custos diretos"],
    ["pgen-tab-vinculos","V\u00ednculos"],
  ];
  abas.forEach(([id,texto])=>{const el=document.getElementById(id);if(el)el.textContent=texto});
  const labels=[
    ["pgen-editor-descricao","Nome do procedimento gen\u00e9rico:"],
    ["pgen-editor-codigo","C\u00f3digo gen\u00e9rico:"],
    ["pgen-editor-especialidade","Especialidade:"],
    ["pgen-editor-simbolo","S\u00edmbolo gr\u00e1fico:"],
    ["pgen-editor-peso","Peso:"],
    ["pgen-editor-obs","Observa\u00e7\u00f5es:"],
  ];
  labels.forEach(([id,texto])=>{
    const label=document.querySelector(`label[for='${id}']`);
    if(label)label.textContent=texto;
  });
  const checkLabel=document.getElementById("pgen-editor-inativo")?.closest("label");
  if(checkLabel&&checkLabel.lastChild)checkLabel.lastChild.textContent="Inativar procedimento";
  const dateLabels=[...pgen.panel.querySelectorAll(".pgen-dates .pgen-field label")];
  if(dateLabels[0])dateLabels[0].textContent="Inclus\u00e3o:";
  if(dateLabels[1])dateLabels[1].textContent="Altera\u00e7\u00e3o:";
  const vincHeads=[...pgen.panel.querySelectorAll(".pgen-vinc-head span")];
  ["Tabela","C\u00f3digo","Nome"].forEach((texto,idx)=>{if(vincHeads[idx])vincHeads[idx].textContent=texto});
  const fasesTitulo=document.querySelector(".pgen-fases-title");
  if(fasesTitulo)fasesTitulo.textContent="Configura fases do procedimento";
  const fasesHeads=[...document.querySelectorAll(".pgen-fases-head-row span")];
  ["Seq","Código","Descrição","Duração"].forEach((texto,idx)=>{if(fasesHeads[idx])fasesHeads[idx].textContent=texto});
  if(pgen?.faseEditTitle&&pgenFaseEditIdx==null)pgen.faseEditTitle.textContent="Nova fase";
  const faseSelectLabel=document.querySelector("label[for='pgen-fase-select']");
  if(faseSelectLabel)faseSelectLabel.textContent="Fase procedimento";
  const faseTempoLabel=document.querySelector("label[for='pgen-fase-tempo']");
  if(faseTempoLabel)faseTempoLabel.textContent="Duração (min)";
};
