function fichaSetSelectValue(el,val){
  if(!el)return;
  const alvo=String(val??"").trim();
  if(!alvo){if(el.options.length)el.selectedIndex=0;return}
  let op=[...el.options].find(x=>String(x.value)===alvo);
  if(!op){
    op=document.createElement("option");
    op.value=alvo;
    op.textContent=alvo;
    el.appendChild(op);
  }
  el.value=alvo;
}
function fichaIsoToInput(value){
  const s=String(value||"").trim();
  if(!s)return"";
  if(/^\d{4}-\d{2}-\d{2}$/.test(s))return s;
  const m=s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if(m)return`${m[3]}-${m[2]}-${m[1]}`;
  const mIso=s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  return mIso?`${mIso[1]}-${mIso[2]}-${mIso[3]}`:"";
}
function fichaInputToApi(value){
  return fichaIsoToInput(value);
}
function fichaDateBr(value){
  const iso=fichaIsoToInput(value);
  if(!iso)return"";
  const [y,m,d]=iso.split("-");
  return`${d}/${m}/${y}`;
}
function fichaAtualizarIdade(){
  if(!ficha||!ficha.idade)return;
  const iso=fichaIsoToInput(ficha.nascimento?.value||"");
  if(!iso){ficha.idade.value="?";return}
  const nasc=new Date(`${iso}T00:00:00`);
  if(Number.isNaN(nasc.getTime())){ficha.idade.value="?";return}
  const hoje=new Date();
  let idade=hoje.getFullYear()-nasc.getFullYear();
  const ajusta=(hoje.getMonth()<nasc.getMonth())||(hoje.getMonth()===nasc.getMonth()&&hoje.getDate()<nasc.getDate());
  if(ajusta)idade-=1;
  ficha.idade.value=idade>=0?String(idade):"?";
}
function fichaSetSelectOptions(selectEl,values,placeholder="Selecione..."){
  if(!selectEl)return;
  const atual=selectEl.value||"";
  const itens=(Array.isArray(values)?values:[]).map(x=>String(x||"").trim()).filter(Boolean);
  const uniq=[...new Set(itens)];
  selectEl.innerHTML=`<option value="">${placeholder}</option>`+uniq.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join("");
  if(atual&&uniq.includes(atual))selectEl.value=atual;
}
function fichaSetUfOptions(selectEl,valorPreferido=""){
  if(!selectEl)return;
  const atual=String(valorPreferido||selectEl.value||"").trim().toUpperCase();
  selectEl.innerHTML=`<option value=""></option>`+FICHA_UFS_PADRAO.map(uf=>`<option value="${uf}">${uf}</option>`).join("");
  if(atual&&FICHA_UFS_PADRAO.includes(atual))selectEl.value=atual;
  else if(!atual)selectEl.value="";
}
function fichaFotoAtualDataUrl(){return String(ficha?.fotoBox?.dataset?.fotoDataUrl||"").trim()}
function fichaFotoAtualNome(){return String(ficha?.fotoBox?.dataset?.fotoNome||"").trim()}
function fichaFotoTemImagem(){return !!fichaFotoAtualDataUrl()}
function fichaFotoAplicar(dataUrl="",nome=""){
  if(!ficha?.fotoBox)return;
  const url=String(dataUrl||"").trim();
  const fileName=String(nome||"").trim();
  ficha.fotoBox.dataset.fotoDataUrl=url;
  ficha.fotoBox.dataset.fotoNome=fileName;
  if(url){
    ficha.fotoBox.innerHTML=`<img src="${esc(url)}" alt="${esc(fileName||"Fotografia do paciente")}" style="width:100%;height:100%;object-fit:cover;display:block">`;
    ficha.fotoBox.title=fileName||"Fotografia do paciente";
    ficha.fotoBox.classList.add("has-photo");
    return;
  }
  ficha.fotoBox.innerHTML="Clique aqui<br>para inserir<br>a fotografia";
  ficha.fotoBox.title="Clique aqui para inserir a fotografia";
  ficha.fotoBox.classList.remove("has-photo");
}
function fichaFotoImportarArquivo(file){
  if(!file)return;
  const reader=new FileReader();
  reader.onload=()=>fichaFotoAplicar(String(reader.result||""),String(file.name||""));
  reader.readAsDataURL(file);
}
function fichaFotoStopStream(){
  const stream=fichaFotoCapture?.stream;
  if(stream&&typeof stream.getTracks==="function")stream.getTracks().forEach(track=>track.stop());
  if(fichaFotoCapture)fichaFotoCapture.stream=null;
}
function fichaFotoFecharCaptura(){
  fichaFotoStopStream();
  if(fichaFotoCapture?.backdrop)fichaFotoCapture.backdrop.classList.add("hidden");
}
async function fichaFotoAtualizarDispositivos(){
  if(!fichaFotoCapture?.device)return [];
  try{
    const devices=await navigator.mediaDevices.enumerateDevices();
    const cameras=devices.filter(d=>d.kind==="videoinput");
    fichaFotoCapture.device.innerHTML=cameras.map((d,idx)=>`<option value="${esc(d.deviceId||"")}">${esc(d.label||`Câmera ${idx+1}`)}</option>`).join("");
    return cameras;
  }catch{
    fichaFotoCapture.device.innerHTML="";
    return [];
  }
}
async function fichaFotoAbrirStream(deviceId=""){
  if(!fichaFotoCapture?.video||!navigator.mediaDevices?.getUserMedia)throw new Error("Captura por câmera não suportada neste navegador.");
  fichaFotoStopStream();
  const constraints=deviceId?{video:{deviceId:{exact:deviceId}}}:{video:{facingMode:"user"}};
  const stream=await navigator.mediaDevices.getUserMedia(constraints);
  fichaFotoCapture.stream=stream;
  fichaFotoCapture.video.srcObject=stream;
  try{await fichaFotoCapture.video.play()}catch{}
  const cameras=await fichaFotoAtualizarDispositivos();
  if(fichaFotoCapture.device&&deviceId)fichaFotoCapture.device.value=deviceId;
  else if(fichaFotoCapture.device&&cameras.length&&!fichaFotoCapture.device.value)fichaFotoCapture.device.value=String(cameras[0].deviceId||"");
}
function fichaFotoCapturarAtual(){
  if(!fichaFotoCapture?.video)return;
  const video=fichaFotoCapture.video;
  const w=video.videoWidth||640;
  const h=video.videoHeight||480;
  const canvas=document.createElement("canvas");
  canvas.width=w;canvas.height=h;
  const ctx=canvas.getContext("2d");
  if(!ctx)return;
  ctx.drawImage(video,0,0,w,h);
  fichaFotoAplicar(canvas.toDataURL("image/jpeg",0.92),`camera-${Date.now()}.jpg`);
  fichaFotoFecharCaptura();
}
