function agendaContatosSelecionarLinha(tr){
  if(!agendaContatos||!(tr instanceof HTMLElement))return;
  agendaContatosSelId=Number(tr.dataset.id||0)||null;
  agendaContatos.tbody.querySelectorAll("tr.selected").forEach(row=>row.classList.remove("selected"));
  if(agendaContatosSelId)tr.classList.add("selected");
}
function agendaContatosNode(tag,{cls,id,text,html,attrs}={},children=[]){
  const el=document.createElement(tag);
  if(cls)el.className=cls;
  if(id)el.id=id;
  if(text!=null)el.textContent=text;
  if(html!=null)el.innerHTML=html;
  if(attrs&&typeof attrs==="object")Object.entries(attrs).forEach(([key,val])=>{if(val!=null)el.setAttribute(key,String(val))});
  (Array.isArray(children)?children:[children]).filter(Boolean).forEach(child=>el.append(child));
  return el;
}
function agendaContatosOption(value,label){
  const opt=document.createElement("option");
  opt.value=String(value??"");
  opt.textContent=label!=null?String(label):String(value??"");
  return opt;
}
function agendaContatosSelect(id,options,{blank=false}={}){
  const select=agendaContatosNode("select",{id});
  if(blank)select.append(agendaContatosOption("",""));
  (Array.isArray(options)?options:[]).forEach(item=>{
    if(item&&typeof item==="object")select.append(agendaContatosOption(item.value,item.label));
    else select.append(agendaContatosOption(item,item));
  });
  return select;
}
function agendaContatosField(labelText,control,{cls=""}={}){
  const wrap=agendaContatosNode("div",{cls:cls?`agenda-field ${cls}`:"agenda-field"});
  wrap.append(agendaContatosNode("label",{text:labelText}),control);
  return wrap;
}
function agendaContatosBuildPhoneRow(selectId,inputId,options){
  return agendaContatosNode("div",{cls:"agenda-phone-row"},[
    agendaContatosSelect(selectId,options),
    agendaContatosNode("input",{id:inputId,attrs:{type:"text"}}),
    agendaContatosNode("div",{cls:"agenda-phone-ico",text:"☎"})
  ]);
}
function agendaContatosGarantirAbaDetalhes(){
  if(!agendaContatos?.paneDetalhes)return;
  if(!agendaContatos.paneDetalhes.querySelector(".agenda-detalhes-top"))agendaContatosReconstruirModalBody();
  agendaContatos.palavra1=agendaContatos.paneDetalhes.querySelector("#agenda-contatos-palavra1");
  agendaContatos.palavra2=agendaContatos.paneDetalhes.querySelector("#agenda-contatos-palavra2");
  agendaContatos.registro=agendaContatos.paneDetalhes.querySelector("#agenda-contatos-registro");
  agendaContatos.especialidade=agendaContatos.paneDetalhes.querySelector("#agenda-contatos-especialidade");
  agendaContatos.observacoes=agendaContatos.paneDetalhes.querySelector("#agenda-contatos-notas");
}
