let auxLayoutDesktopAplicado=false;
function auxTipoEh(tipo,chave){
  const txt=String(tipo||"").toLowerCase();
  if(chave==="especialidade")return txt.includes("especialidade");
  if(chave==="situacao_agendamento")return txt.includes("agendamento");
  if(chave==="situacao_paciente")return txt.includes("paciente");
  if(chave==="grupo_medicamento")return txt.includes("grupo")&&txt.includes("medicamento");
  return false;
}
function auxNormalizarHexCor(value){
  const raw=String(value??"").trim();
  if(!raw)return"";
  const hex=raw.replace(/^0x/i,"").replace(/^#/,"");
  const withHash=`#${hex}`;
  return /^#[0-9a-fA-F]{6}$/.test(withHash)?withHash.toLowerCase():"";
}
function auxCorrigirMojibake(texto){
  const bruto=String(texto??"").trim();
  if(!/[ÃÂ]/.test(bruto))return bruto;
  try{return decodeURIComponent(escape(bruto))}catch{return bruto}
}
function auxCorApresentacaoFonteSistema(){
  const origem=(typeof prestAgendaApresCorOptions==="function")?prestAgendaApresCorOptions():[];
  const lista=Array.isArray(origem)?origem:[];
  const out=[];
  const seen=new Set();
  lista.forEach(item=>{
    const hex=auxNormalizarHexCor(item?.value||item?.hex||"");
    if(!hex||seen.has(hex))return;
    seen.add(hex);
    const label=auxCorrigirMojibake(item?.label||item?.nome||hex.toUpperCase());
    out.push({hex,label:label||hex.toUpperCase()});
  });
  return out;
}
function auxCorApresentacaoNormLabelKey(texto){
  return String(texto||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-zA-Z ]/g,"").toLowerCase().trim();
}
function auxCorApresentacaoHexPorLabel(label){
  const chave=auxCorApresentacaoNormLabelKey(auxCorrigirMojibake(label));
  if(!chave)return"";
  const item=auxCorApresentacaoFonteSistema().find(x=>auxCorApresentacaoNormLabelKey(x.label)===chave);
  return item?.hex||"";
}
function auxCorApresentacaoOpcoesHtml(corAtual){
  const selecionada=auxNormalizarHexCor(corAtual)||"#000000";
  const cores=[...auxCorApresentacaoFonteSistema()];
  if(!cores.some(item=>item.hex===selecionada)){
    cores.push({label:selecionada.toUpperCase(),hex:selecionada});
  }
  return cores.map(item=>{
    const hex=auxNormalizarHexCor(item.hex||"");
    const selected=hex===selecionada?"selected":"";
    const label=auxCorrigirMojibake(String(item.label||"").trim())||hex.toUpperCase();
    return `<option value="${esc(hex)}" ${selected}>${esc(label)}</option>`;
  }).join("");
}
function auxCorApresentacaoCorLabel(hex){
  const cor=auxNormalizarHexCor(hex);
  if(!cor)return"(Sem cor)";
  const item=auxCorApresentacaoFonteSistema().find(x=>x.hex===cor);
  return item?.label||cor.toUpperCase();
}
let auxCorComboBound=false;
function auxCorApresentacaoGarantirEstiloCombo(){
  const styleId="aux-cor-combo-style";
  if(document.getElementById(styleId))return;
  const style=document.createElement("style");
  style.id=styleId;
  style.textContent=
    ".aux-cor-native-hidden{display:none!important}" +
    ".aux-cor-combo{position:relative;width:100%;font:11px Tahoma,sans-serif}" +
    ".aux-cor-btn{width:100%;height:22px;border:1px solid #7f9db9;background:#fff;display:grid;grid-template-columns:1fr 18px;align-items:center;padding:0 3px;box-sizing:border-box;cursor:pointer}" +
    ".aux-cor-swatch{width:16px;height:12px;border:1px solid #222;display:inline-block;box-sizing:border-box}" +
    ".aux-cor-label{text-align:left;padding-left:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}" +
    ".aux-cor-arrow{height:100%;display:flex;align-items:center;justify-content:center;border-left:1px solid #9eb6ce;background:#dbe8f6;color:#2b4b6f;font-size:10px;line-height:1}" +
    ".aux-cor-list{position:absolute;left:0;top:21px;width:100%;max-height:none;overflow:visible;background:#f3f3f3;border:1px solid #2b8ae2;box-sizing:border-box;z-index:12050}" +
    ".aux-cor-item{height:24px;display:grid;grid-template-columns:20px 1fr;align-items:center;gap:4px;padding:0 4px;box-sizing:border-box;cursor:pointer}" +
    ".aux-cor-item:hover{background:#d9e8fb}" +
    ".aux-cor-item.active{background:#0078d7;color:#fff}" +
    ".aux-cor-hidden{display:none}";
  document.head.appendChild(style);
}
function auxCorApresentacaoFecharListas(except){
  document.querySelectorAll(".aux-cor-list").forEach(list=>{
    if(except&&list===except)return;
    list.classList.add("aux-cor-hidden");
  });
}
function auxCorApresentacaoMontarCombo(select){
  if(!(select instanceof HTMLSelectElement))return null;
  auxCorApresentacaoGarantirEstiloCombo();
  if(!auxCorComboBound){
    document.addEventListener("click",ev=>{
      const tgt=ev.target;
      if(!(tgt instanceof Element)||!tgt.closest(".aux-cor-combo"))auxCorApresentacaoFecharListas();
    });
    document.addEventListener("keydown",ev=>{
      if(ev.key==="Escape")auxCorApresentacaoFecharListas();
    });
    auxCorComboBound=true;
  }
  [...select.options].forEach(opt=>{
    const hex=auxNormalizarHexCor(opt.value||"");
    const rotulo=auxCorApresentacaoCorLabel(hex)||auxCorrigirMojibake(opt.textContent||"");
    const corPorLabel=auxCorApresentacaoHexPorLabel(rotulo);
    opt.dataset.auxCor=corPorLabel||hex||"#ffffff";
    opt.textContent=rotulo;
    if(hex)opt.value=hex;
  });
  const holder=select.parentElement;
  if(!(holder instanceof HTMLElement))return null;
  const cadModal=select.closest("#cad-modal-backdrop .cad-modal");
  if(cadModal instanceof HTMLElement){
    cadModal.style.overflow="visible";
    const cadBody=cadModal.querySelector("#cad-modal-body");
    if(cadBody instanceof HTMLElement)cadBody.style.overflow="visible";
  }
  let combo=holder.querySelector(".aux-cor-combo");
  if(!(combo instanceof HTMLElement)){
    combo=document.createElement("div");
    combo.className="aux-cor-combo";
    combo.innerHTML=[
      '<button type="button" class="aux-cor-btn">',
      '<span class="aux-cor-label"></span>',
      '<span class="aux-cor-arrow">â–¼</span>',
      "</button>",
      '<div class="aux-cor-list aux-cor-hidden"></div>',
    ].join("");
    holder.appendChild(combo);
  }
  const btn=combo.querySelector(".aux-cor-btn");
  const lb=combo.querySelector(".aux-cor-label");
  const list=combo.querySelector(".aux-cor-list");
  if(!(btn instanceof HTMLButtonElement)||!(lb instanceof HTMLElement)||!(list instanceof HTMLDivElement))return null;
  const posicionarLista=()=>{
    const rect=btn.getBoundingClientRect();
    list.style.position="fixed";
    list.style.left=`${Math.round(rect.left)}px`;
    list.style.top=`${Math.round(rect.bottom-1)}px`;
    list.style.width=`${Math.max(120,Math.round(rect.width))}px`;
    list.style.maxHeight="300px";
    list.style.overflowY="auto";
    list.style.overflowX="hidden";
    list.style.zIndex="12050";
    list.style.bottom="auto";
  };
  const syncHead=()=>{
    const opt=select.selectedOptions&&select.selectedOptions[0]?select.selectedOptions[0]:null;
    lb.textContent=String(opt?.textContent||"");
  };
  const renderList=()=>{
    list.innerHTML="";
    [...select.options].forEach((opt,idx)=>{
      const item=document.createElement("div");
      item.className="aux-cor-item"+(idx===select.selectedIndex?" active":"");
      item.innerHTML=[
        `<span class="aux-cor-swatch" style="background:${esc(String(opt.dataset.auxCor||"#ffffff"))}"></span>`,
        `<span class="aux-cor-label">${esc(String(opt.textContent||""))}</span>`,
      ].join("");
      item.addEventListener("click",()=>{
        select.selectedIndex=idx;
        select.dispatchEvent(new Event("change",{bubbles:true}));
        syncHead();
        renderList();
        auxCorApresentacaoFecharListas();
      });
      list.appendChild(item);
    });
  };
  btn.onclick=ev=>{
    ev.stopPropagation();
    const abrir=list.classList.contains("aux-cor-hidden");
    if(abrir){
      posicionarLista();
      list.scrollTop=0;
    }
    auxCorApresentacaoFecharListas(abrir?list:null);
    list.classList.toggle("aux-cor-hidden",!abrir);
  };
  select.classList.add("aux-cor-native-hidden");
  if(!select.dataset.auxCorBound){
    select.addEventListener("change",()=>{
      syncHead();
      renderList();
    });
    window.addEventListener("resize",()=>{
      if(!list.classList.contains("aux-cor-hidden"))posicionarLista();
    });
    window.addEventListener("scroll",()=>{
      if(!list.classList.contains("aux-cor-hidden"))posicionarLista();
    },true);
    select.dataset.auxCorBound="1";
  }
  syncHead();
  renderList();
  return combo;
}
function auxGerarCodigoAutomatico(){
  let maxNum=0;
  let width=2;
  for(const item of Array.isArray(auxItensCache)?auxItensCache:[]){
    const codigo=String(item?.codigo??"").trim();
    if(!/^\d+$/.test(codigo))continue;
    maxNum=Math.max(maxNum,Number(codigo));
    width=Math.max(width,codigo.length);
  }
  return String(maxNum+1).padStart(width,"0");
}
async function auxPosSalvarDependencias(tipo){
  if(!auxTipoEh(tipo,"situacao_agendamento"))return;
  if(typeof agendaLegadoRecarregarStatus==="function"){
    try{await agendaLegadoRecarregarStatus()}catch{}
  }
  if(typeof agendaSemanaRenderEventos==="function"){
    try{agendaSemanaRenderEventos()}catch{}
  }
}
