if(sa&&sa.tbClinicas)sa.tbClinicas.addEventListener("click",async(ev)=>{
  const btn=ev.target.closest("button[data-sa-action]");
  if(!btn)return;
  const id=Number(btn.dataset.id||0);
  if(!id)return;
  const action=btn.dataset.saAction||"";
  if(action==="toggle"){
    const item=saClinicasCache.find(x=>x.id===id);
    if(!item)return;
    await saAlterarStatusClinica(id,!item.ativo);
    return;
  }
  if(action==="trial-extra"){
    const row=btn.closest("tr[data-id]");
    const inp=row?row.querySelector(`input[data-sa-days-id="${id}"]`):null;
    const dias=Number(inp?.value||0);
    await saProrrogarTesteClinica(id,dias);
    return;
  }
  if(action==="demo"){await saAlterarPlanoClinica(id,"DEMO");return}
  if(action==="mensal"){await saAlterarPlanoClinica(id,"MENSAL");return}
  if(action==="anual"){await saAlterarPlanoClinica(id,"ANUAL");return}
  if(action==="superadmin"){await saAlterarPlanoClinica(id,"SUPERADMIN");return}
  if(action==="novo-user"){await saCriarUsuarioClinica(id);return}
  if(action==="excluir-clinica"){await saExcluirClinica(id);return}
});
