// Overrides - Ficha anamnese respostas + impressão
let fichaAnamneseCache=[];
let fichaAnamneseSelId=null;
let fichaAnamneseQuestionarioId=null;
let fichaAnamneseQuestionarioNome="";
function fichaAnamnesePodeImprimir(){
  return String(sessaoAtual?.email||"").trim().toLowerCase()==="gleissontel@gmail.com";
}
function fichaAnamneseSelecionado(){return fichaAnamneseCache.find(x=>x.pergunta_id===fichaAnamneseSelId)||null}
function fichaAnamneseRender(){
  if(!ficha?.anamneseList)return;
  ficha.anamneseList.innerHTML=fichaAnamneseCache.map(item=>{
    const resp=String(item.resposta||"").trim();
    const cls=item.pergunta_id===fichaAnamneseSelId?"selected":"";
    const badge=resp?"<span style=\"color:#0f766e;font-weight:700\">•</span> ":"";
    return`<tr data-id="${item.pergunta_id}" class="${cls}"><td>${badge}${esc(item.texto||"")}</td></tr>`;
  }).join("");
  if(ficha.anamneseAlerta){
    const alertas=fichaAnamneseCache.filter(x=>String(x.resposta||"").trim()).length;
    ficha.anamneseAlerta.textContent=alertas?`Anamnese com ${alertas} respostas registradas.`:"Sem alertas de anamnese para este paciente.";
  }
}
function fichaAnamneseSelecionar(id){
  fichaAnamneseSelId=Number(id||0)||null;
  const sel=fichaAnamneseSelecionado();
  if(ficha?.anamneseResposta)ficha.anamneseResposta.value=sel?String(sel.resposta||""):"";
  fichaAnamneseRender();
}
async function fichaAnamneseCarregar(){
  if(!fichaPacienteAtualId||!ficha?.anamneseList){
    fichaAnamneseCache=[];fichaAnamneseSelId=null;fichaAnamneseQuestionarioId=null;fichaAnamneseQuestionarioNome="";
    if(ficha?.anamneseList)ficha.anamneseList.innerHTML="";
    if(ficha?.anamneseResposta)ficha.anamneseResposta.value="";
    if(ficha?.anamneseAlerta)ficha.anamneseAlerta.textContent="Sem alertas de anamnese para este paciente.";
    return;
  }
  const q=Number(fichaAnamneseQuestionarioId||0)||"";
  const url=q?`/anamnese/pacientes/${fichaPacienteAtualId}/respostas?questionario_id=${q}`:`/anamnese/pacientes/${fichaPacienteAtualId}/respostas`;
  const{res,data}=await requestJson("GET",url,undefined,true);
  if(!res.ok){
    if(ficha?.anamneseAlerta)ficha.anamneseAlerta.textContent=data.detail||"Falha ao carregar anamnese.";
    return;
  }
  fichaAnamneseQuestionarioId=data.questionario_id||null;
  fichaAnamneseQuestionarioNome=data.questionario_nome||"";
  fichaAnamneseCache=Array.isArray(data.itens)?data.itens:[];
  fichaAnamneseSelId=fichaAnamneseCache[0]?.pergunta_id||null;
  fichaAnamneseRender();
  const sel=fichaAnamneseSelecionado();
  if(ficha?.anamneseResposta)ficha.anamneseResposta.value=sel?String(sel.resposta||""):"";
}
async function fichaAnamneseSalvarSelecionada(){
  if(!fichaPacienteAtualId)return;
  const sel=fichaAnamneseSelecionado();
  if(!sel)return;
  const resposta=String(ficha?.anamneseResposta?.value||"");
  const payload={pergunta_id:sel.pergunta_id,resposta};
  const{res,data}=await requestJson("PUT",`/anamnese/pacientes/${fichaPacienteAtualId}/respostas`,payload,true);
  if(!res.ok){
    window.alert(data.detail||"Falha ao salvar resposta.");
    return;
  }
  sel.resposta=resposta;
  fichaAnamneseRender();
}
function fichaAnamneseImprimir(){
  if(!fichaAnamnesePodeImprimir()){
    window.alert("Impressao de anamnese disponivel apenas para a conta gleissontel@gmail.com.");
    return;
  }
  const nome=String(ficha?.titulo?.textContent||"Ficha de anamnese").replace("Ficha pessoal -","").trim()||"Paciente";
  const dataHoje=(new Date()).toLocaleDateString("pt-BR");
  const itens=fichaAnamneseCache.map(item=>({
    numero:item.numero,
    texto:item.texto,
    resposta:String(item.resposta||"").trim()
  }));
  const linhas=itens.map(x=>`<tr><td class="num">${x.numero}</td><td class="pergunta">${esc(x.texto||"")}</td><td class="resposta">${esc(x.resposta||"")}</td></tr>`).join("");
  const html=`<!doctype html><html><head><meta charset="utf-8"><title>Anamnese</title><style>
    body{font:12px Tahoma, sans-serif;color:#111;margin:24px}
    h1{font-size:16px;margin:0 0 6px}
    .meta{margin:0 0 14px;color:#444}
    table{width:100%;border-collapse:collapse}
    th,td{border:1px solid #cfd6de;padding:6px;vertical-align:top}
    th{background:#f1f5f9;text-align:left}
    .num{width:40px;text-align:center}
    .resposta{width:40%}
  </style></head><body>
    <h1>Ficha de anamnese</h1>
    <div class="meta">Paciente: ${esc(nome)}<br>Data: ${dataHoje}</div>
    <table><thead><tr><th style="width:40px">Nº</th><th>Pergunta</th><th>Resposta</th></tr></thead><tbody>${linhas}</tbody></table>
  </body></html>`;
  const win=window.open("","anamnese-print");
  if(!win){window.alert("Nao foi possivel abrir a janela de impressao.");return}
  win.document.open();win.document.write(html);win.document.close();
  win.focus();win.print();
}
const _fichaEnsureUIOrig=fichaEnsureUI;
fichaEnsureUI=function(){_fichaEnsureUIOrig();if(!ficha)return;if(ficha.anamneseList&&ficha.anamneseList.dataset.bound!=="1"){ficha.anamneseList.dataset.bound="1";ficha.anamneseList.addEventListener("click",ev=>{const tr=ev.target.closest("tr[data-id]");if(!tr)return;fichaAnamneseSelecionar(tr.dataset.id)});}if(ficha.anamneseResposta&&ficha.anamneseResposta.dataset.bound!=="1"){ficha.anamneseResposta.dataset.bound="1";ficha.anamneseResposta.addEventListener("blur",()=>{fichaAnamneseSalvarSelecionada();});}if(ficha.anamneseAtualizar&&ficha.anamneseAtualizar.dataset.bound!=="1"){ficha.anamneseAtualizar.dataset.bound="1";ficha.anamneseAtualizar.addEventListener("click",async()=>{await fichaAnamneseSalvarSelecionada();await fichaAnamneseCarregar();if(fichaAnamnesePodeImprimir())fichaAnamneseImprimir();});}};
const _fichaAplicarPacienteOrig=fichaAplicarPaciente;
fichaAplicarPaciente=function(item){_fichaAplicarPacienteOrig(item);fichaAnamneseCarregar();};
const _fichaLimparNovoOrig=fichaLimparNovo;
fichaLimparNovo=async function(){await _fichaLimparNovoOrig();fichaAnamneseCache=[];fichaAnamneseSelId=null;fichaAnamneseQuestionarioId=null;fichaAnamneseQuestionarioNome="";if(ficha?.anamneseList)ficha.anamneseList.innerHTML="";if(ficha?.anamneseResposta)ficha.anamneseResposta.value="";if(ficha?.anamneseAlerta)ficha.anamneseAlerta.textContent="Sem alertas de anamnese para este paciente.";};
const _fichaSetTabOrig=fichaSetTab;
fichaSetTab=function(tab){_fichaSetTabOrig(tab);if(tab==="anamnese")fichaAnamneseCarregar();};

// Overrides - Simbolos graficos CRUD
const SIMBOLOS_TIPO_MARCA_OPCOES=[
  {value:1,label:"Face (ex: Restauração)"},
  {value:2,label:"Dente (ex: Coroa)"},
  {value:3,label:"Grupo (ex: Prótese-fixa)"},
  {value:4,label:"Arcada (ex: Prótese-total)"},
  {value:5,label:"Geral (ex: Profilaxia)"},
  {value:6,label:"Segmento (ex: Bracket)"},
];
function simbolosSetModalCodigo(codigo){if(!simbolosCfg)return;simbolosCfg.modalBackdrop.dataset.codigo=String(codigo||"").trim();}
function simbolosCodigoSelecionado(){return (simbolosCfg?.modalBackdrop?.dataset?.codigo||"").trim();}
function simbolosSetModalRefId(id){if(!simbolosCfg?.modalBackdrop)return;const v=Number(id||0)||0;if(v>0)simbolosCfg.modalBackdrop.dataset.refId=String(v);else delete simbolosCfg.modalBackdrop.dataset.refId}
function simbolosRefIdSelecionado(){return Number(simbolosCfg?.modalBackdrop?.dataset?.refId||0)||0}
function simbolosNormalizarTexto(valor){return String(valor||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").trim().toLowerCase()}
function simbolosEspecialidadePadrao(){
  if(!simbolosCfg?.modalEspecialidade)return"";
  const opcoes=[...simbolosCfg.modalEspecialidade.options];
  const dent=opcoes.find(opt=>simbolosNormalizarTexto(opt.textContent)==="dentistica");
  return String(dent?.value||opcoes[0]?.value||"");
}
function simbolosPreencherFormas(){
  if(!simbolosCfg?.modalForma)return;
  simbolosCfg.modalForma.innerHTML=SIMBOLOS_TIPO_MARCA_OPCOES.map(item=>`<option value="${item.value}">${esc(item.label)}</option>`).join("");
}
function simbolosSetModalForma(tipoMarca){
  if(!simbolosCfg?.modalForma)return;
  const valor=Number(tipoMarca||0);
  const existe=SIMBOLOS_TIPO_MARCA_OPCOES.some(item=>item.value===valor);
  simbolosCfg.modalForma.value=String(existe?valor:2);
}
function simbolosTipoMarcaSelecionado(){
  const valor=Number(simbolosCfg?.modalForma?.value||0);
  return valor>0?valor:null;
}
function simbolosEspecialidadeValorPorTexto(texto){
  const alvo=simbolosNormalizarTexto(texto);
  if(!alvo||!simbolosCfg?.modalEspecialidade)return "";
  const match=[...simbolosCfg.modalEspecialidade.options].find(opt=>{
    return simbolosNormalizarTexto(opt.textContent)===alvo||String(opt.value||"").trim()===String(texto||"").trim();
  });
  return String(match?.value||"");
}
function simbolosEspecialidadeResolverValor(valor){
  const bruto=String(valor??"").trim();
  if(!bruto||!simbolosCfg?.modalEspecialidade)return "";
  const direto=[...simbolosCfg.modalEspecialidade.options].find(opt=>String(opt.value||"").trim()===bruto);
  if(direto)return String(direto.value||"");
  const numerico=/^\d+$/.test(bruto)?String(Number(bruto)):null;
  if(numerico){
    const porNumero=[...simbolosCfg.modalEspecialidade.options].find(opt=>String(Number(opt.value||NaN))===numerico);
    if(porNumero)return String(porNumero.value||"");
  }
  const porTexto=simbolosEspecialidadeValorPorTexto(simbolosEspecialidadeNome(bruto)||bruto);
  return String(porTexto||"");
}
function simbolosTipoMarcaPorTexto(texto){
  const alvo=simbolosNormalizarTexto(texto);
  if(!alvo)return null;
  const match=SIMBOLOS_TIPO_MARCA_OPCOES.find(item=>{
    return simbolosNormalizarTexto(item.label)===alvo||String(item.value)===String(texto||"").trim();
  });
  return match?Number(match.value):null;
}
function simbolosEhSistema(item){return !!item&&(Number(item.legacy_id||0)>0||Number(item.tipo_simbolo||0)===1)}
function simbolosAtualizarAcoesPainel(){
  if(!simbolosCfg)return;
  const item=simbolosSelecionado();
  const bloqueado=!item||simbolosEhSistema(item);
  if(simbolosCfg.btnEditar){
    simbolosCfg.btnEditar.disabled=!item;
    simbolosCfg.btnEditar.style.opacity=item?"1":".55";
  }
  if(simbolosCfg.btnExcluir){
    simbolosCfg.btnExcluir.disabled=bloqueado;
    simbolosCfg.btnExcluir.style.opacity=bloqueado?".55":"1";
  }
}
function simbolosAtualizarSelecaoBiblioteca(ref={}){
  if(!simbolosCfg?.biblioteca)return;
  const idSel=Number(ref.id||0)||0;
  const codigoSel=String(ref.codigo||"").trim().toLowerCase();
  [...simbolosCfg.biblioteca.querySelectorAll("button[data-id]")].forEach(btn=>{
    const item=simbolosBibliotecaCache.find(x=>Number(x.id||0)===Number(btn.dataset.id||0));
    const codigoItem=String(item?.codigo||"").trim().toLowerCase();
    const sel=(idSel>0&&Number(btn.dataset.id||0)===idSel)||(!idSel&&codigoSel&&codigoItem===codigoSel);
    btn.classList.toggle("selected",sel);
  });
}
function simbolosLimparImagemEditada(){
  if(!simbolosCfg?.modalBackdrop)return;
  delete simbolosCfg.modalBackdrop.dataset.customImage;
}
function simbolosAplicarImagemEditada(dataUrl){
  if(!simbolosCfg?.modalBackdrop)return;
  const valor=String(dataUrl||"").trim();
  if(!valor){simbolosLimparImagemEditada();simbolosAtualizarPreview(simbolosCodigoSelecionado());return}
  simbolosCfg.modalBackdrop.dataset.customImage=valor;
  const canvas=simbolosCfg.modalBackdrop.querySelector(".simbolos-canvas");
  if(!canvas)return;
  const nome=(simbolosCfg?.modalNome?.value||"Simbolo grafico").trim()||"Simbolo grafico";
  canvas.innerHTML=`<img src="${esc(valor)}" alt="${esc(nome)}" style="width:100%;height:100%;object-fit:contain;display:block">`;
}
function simbolosEditorNotificar(type,payload={}){
  try{
    const frameWin=simbolosCfg?.editorFrame?.contentWindow;
    if(frameWin)frameWin.postMessage({type,...payload},window.location.origin);
  }catch{}
}
function simbolosAtualizarPreview(codigo){
  const canvas=simbolosCfg?.modalBackdrop?.querySelector(".simbolos-canvas");
  if(!canvas)return;
  const imagemEditada=String(simbolosCfg?.modalBackdrop?.dataset?.customImage||"").trim();
  if(imagemEditada){
    const nome=(simbolosCfg?.modalNome?.value||"Simbolo grafico").trim()||"Simbolo grafico";
    canvas.innerHTML=`<img src="${esc(imagemEditada)}" alt="${esc(nome)}" style="width:100%;height:100%;object-fit:contain;display:block">`;
    return;
  }
  const chave=String(codigo||"").trim().toLowerCase();
  const editId=Number(simbolosCfg?.modalBackdrop?.dataset?.editId||0)||0;
  const itemPorModal=editId?simbolosCache.find(x=>Number(x.id||0)===editId)||null:null;
  const refId=simbolosRefIdSelecionado();
  const itemPorRef=refId?(simbolosBibliotecaCache.find(x=>Number(x.id||0)===refId)||simbolosCache.find(x=>Number(x.id||0)===refId)||null):null;
  const item=itemPorModal||itemPorRef||simbolosBibliotecaCache.find(x=>String(x.codigo||"").trim().toLowerCase()===chave)||simbolosCache.find(x=>String(x.codigo||"").trim().toLowerCase()===chave)||null;
  const imagem=simbolosImagemUrl(item);
  if(imagem){
    canvas.innerHTML=`<img src="${esc(imagem)}" alt="${esc(String(item?.descricao||"Simbolo grafico"))}" style="width:100%;height:100%;object-fit:contain;display:block">`;
    return;
  }
  canvas.innerHTML="";
}
function simbolosImagemUrl(item){
  const imagem=String(item?.imagem_url||"").trim();
  const codigo=String(item?.codigo||"").trim().toLowerCase();
  if(codigo==="sim_modelo.bmp")return "/desktop-assets/easy/sim_default.bmp";
  return imagem;
}
function simbolosBibliotecaOculta(item){
  const codigo=String(item?.codigo||"").trim().toLowerCase();
  return codigo==="int_escova.bmp"||codigo==="int_manut.bmp"||codigo==="int_remove.bmp"||codigo==="int_resto.bmp";
}
function simbolosCompararBiblioteca(a,b){
  return String(a?.codigo||"").localeCompare(String(b?.codigo||""),undefined,{numeric:true,sensitivity:"base"});
}
function simbolosDialogFechar(resposta){
  if(!simbolosCfg?.msgBackdrop)return;
  const resolver=simbolosCfg.msgBackdrop._resolver;
  simbolosCfg.msgBackdrop._resolver=null;
  simbolosCfg.msgBackdrop.classList.add("hidden");
  if(typeof resolver==="function")resolver(!!resposta);
}
function simbolosDialogPergunta(texto){
  if(!simbolosCfg?.msgBackdrop||!simbolosCfg?.msgText)return Promise.resolve(false);
  simbolosCfg.msgText.textContent=String(texto||"");
  simbolosCfg.msgBackdrop.classList.remove("hidden");
  return new Promise(resolve=>{simbolosCfg.msgBackdrop._resolver=resolve});
}
function simbolosDialogInfo(texto){
  if(!simbolosCfg?.msgBackdrop||!simbolosCfg?.msgText)return Promise.resolve();
  simbolosCfg.msgText.textContent=String(texto||"");
  if(simbolosCfg.msgSim){simbolosCfg.msgSim.classList.add("hidden")}
  if(simbolosCfg.msgNao){simbolosCfg.msgNao.textContent="Fechar"}
  simbolosCfg.msgBackdrop.classList.remove("hidden");
  return new Promise(resolve=>{
    simbolosCfg.msgBackdrop._resolver=()=>resolve();
  }).finally(()=>{
    if(simbolosCfg.msgSim){simbolosCfg.msgSim.classList.remove("hidden")}
    if(simbolosCfg.msgNao){simbolosCfg.msgNao.textContent="Não"}
  });
}
function simbolosItemModalAtual(){
  const editId=Number(simbolosCfg?.modalBackdrop?.dataset?.editId||0)||0;
  if(!editId)return null;
  return simbolosCache.find(x=>Number(x.id||0)===editId)||null;
}
async function simbolosExcluirModalAtual(){
  const editId=Number(simbolosCfg?.modalBackdrop?.dataset?.editId||0)||0;
  if(!editId){
    return false;
  }
  const itemModal=simbolosCache.find(x=>Number(x.id||0)===editId)||null;
  const nomeSimbolo=String(simbolosCfg?.modalNome?.value||itemModal?.descricao||"").trim()||"este simbolo";
  const confirmou=await simbolosDialogPergunta(`Deseja eliminar o simbolo ${nomeSimbolo}?`);
  if(!confirmou)return false;
  const{res,data}=await requestJson("DELETE",`/cadastros/simbolos-graficos/${editId}`,undefined,true);
  if(!res.ok){
    window.alert(data.detail||"Falha ao eliminar simbolo.");
    return false;
  }
  delete simbolosCfg.modalBackdrop.dataset.editId;
  simbolosSetModalRefId(0);
  simbolosSetModalCodigo("");
  simbolosLimparImagemEditada();
  simbolosRemoverDoCache(editId);
  simbolosFecharEditor();
  simbolosFecharModal();
  await simbolosCarregar();
  return true;
}
async function simbolosPersistirEdicao(payloadEntrada={}){
  if(!simbolosCfg?.modalBackdrop)return{ok:false};
  const nome=String(payloadEntrada.nome||simbolosCfg.modalNome?.value||"").trim();
  const especialidadeTexto=String(payloadEntrada.especialidade||"").trim();
  const formaTexto=String(payloadEntrada.forma||"").trim();
  const salvarComo=!!payloadEntrada.saveAs;
  const imagemCustom=String(payloadEntrada.image||simbolosCfg.modalBackdrop.dataset.customImage||"").trim()||null;
  const editId=Number(simbolosCfg.modalBackdrop.dataset.editId||0)||0;
  const itemAtual=editId?simbolosCache.find(x=>Number(x.id||0)===editId)||null:null;
  const sistema=simbolosEhSistema(itemAtual);
  const codigo=String(simbolosCodigoSelecionado()||itemAtual?.codigo||"").trim();
  const especialidade=simbolosEspecialidadeValorPorTexto(especialidadeTexto)||String(simbolosCfg?.modalEspecialidade?.value||"").trim();
  const tipoMarca=simbolosTipoMarcaPorTexto(formaTexto)||simbolosTipoMarcaSelecionado();
  if(!nome||!especialidade||!tipoMarca){
    return{ok:false,message:"Nao pode salvar sem ter campos preenchidos."};
  }
  if(sistema&&itemAtual){
    const {res,data}=await requestJson("PUT",`/cadastros/simbolos-graficos/${itemAtual.id}`,{
      descricao:nome,
      especialidade:Number(especialidade),
    },true);
    if(!res.ok){
      return{ok:false,message:data.detail||"Falha ao salvar simbolo."};
    }
    const savedId=Number(data?.id||itemAtual?.id||0)||0;
    const savedNome=String(data?.descricao||nome||"").trim();
    simbolosCfg.modalBackdrop.dataset.editId=savedId?String(savedId):"";
    if(simbolosCfg.modalNome)simbolosCfg.modalNome.value=savedNome;
    if(simbolosCfg.modalEspecialidade)simbolosCfg.modalEspecialidade.value=String(especialidade);
    await simbolosCarregar();
    if(savedId){
      simbolosSelId=savedId;
      simbolosRender();
    }
    return{ok:true,id:savedId,codigo:String(itemAtual?.codigo||""),descricao:savedNome,message:"Simbolo atualizado com sucesso.",created:false};
  }
  if(!codigo){
    return{ok:false,message:"Selecione um simbolo na biblioteca."};
  }
  if(nome.localeCompare(codigo,undefined,{sensitivity:"base"})===0||/\.bmp$/i.test(nome)){
    return{ok:false,message:"Informe um nome proprio para o simbolo, diferente do arquivo base."};
  }
  const salvandoExistente=!!itemAtual&&!sistema&&!salvarComo;
  const nomeDuplicado=simbolosCache.some(x=>{
    const mesmoNome=String(x?.descricao||"").trim().localeCompare(nome,undefined,{sensitivity:"base"})===0;
    if(!mesmoNome)return false;
    if(salvandoExistente&&Number(x?.id||0)===Number(itemAtual?.id||0))return false;
    return true;
  });
  if(nomeDuplicado){
    return{ok:false,message:"Ja existe este nome, tente outro."};
  }
  const requestPayload={
    descricao:nome,
    codigo,
    especialidade:Number(especialidade),
    tipo_simbolo:2,
    tipo_marca:Number(tipoMarca),
    imagem_custom:imagemCustom,
  };
  const method=salvandoExistente?"PUT":"POST";
  const path=salvandoExistente?`/cadastros/simbolos-graficos/${itemAtual.id}`:"/cadastros/simbolos-graficos";
  const {res,data}=await requestJson(method,path,requestPayload,true);
  if(!res.ok){
    return{ok:false,message:data.detail||"Falha ao salvar simbolo."};
  }
  const savedId=Number(data?.id||itemAtual?.id||0)||0;
  const savedCodigo=String(data?.codigo||codigo||"").trim();
  const savedNome=String(data?.descricao||nome||"").trim();
  const mensagemSucesso=salvandoExistente?"Desenho salvo com sucesso.":(salvarComo?"Copia do simbolo criada com sucesso.":"Novo simbolo criado com sucesso.");
  simbolosCfg.modalBackdrop.dataset.editId=savedId?String(savedId):"";
  simbolosSetModalRefId(savedId||0);
  simbolosSetModalCodigo(savedCodigo);
  if(simbolosCfg.modalNome)simbolosCfg.modalNome.value=savedNome;
  if(simbolosCfg.modalEspecialidade)simbolosCfg.modalEspecialidade.value=String(especialidade);
  simbolosSetModalForma(tipoMarca);
  if(imagemCustom)simbolosAplicarImagemEditada(imagemCustom);else simbolosLimparImagemEditada();
  await simbolosCarregar();
  if(savedId){
    simbolosSelId=savedId;
    simbolosRender();
  }
  simbolosAtualizarSelecaoBiblioteca({id:savedId||0,codigo:savedCodigo});
  simbolosAtualizarPreview(savedCodigo);
  return{ok:true,id:savedId,codigo:savedCodigo,descricao:savedNome,message:mensagemSucesso,created:!salvandoExistente};
}
function simbolosModalEhSistema(){
  return simbolosEhSistema(simbolosItemModalAtual());
}
function simbolosAplicarModoModal(item){
  if(!simbolosCfg)return;
  const sistema=simbolosEhSistema(item);
  const radios=[...simbolosCfg.modalBackdrop.querySelectorAll("input[name='simbolos-tipo']")];
  radios.forEach(r=>{r.checked=sistema? r.value==="sistema": r.value==="usuario";r.disabled=true});
  if(simbolosCfg.modalNome)simbolosCfg.modalNome.disabled=false;
  if(simbolosCfg.modalEspecialidade)simbolosCfg.modalEspecialidade.disabled=false;
  if(simbolosCfg.modalForma)simbolosCfg.modalForma.disabled=sistema;
  const btnClear=simbolosCfg.modalBackdrop.querySelector("#simbolos-desenho-clear");
  const btnEdit=simbolosCfg.modalBackdrop.querySelector("#simbolos-desenho-edit");
  if(btnClear){btnClear.disabled=sistema;btnClear.style.opacity=sistema?".45":"1"}
  if(btnEdit){btnEdit.disabled=sistema;btnEdit.style.opacity=sistema?".45":"1"}
  const canvas=simbolosCfg.modalBackdrop.querySelector(".simbolos-canvas");
  if(canvas)canvas.style.opacity=sistema?".8":"1";
  if(simbolosCfg.biblioteca){
    simbolosCfg.biblioteca.style.pointerEvents=sistema?"none":"auto";
    simbolosCfg.biblioteca.style.opacity=sistema?".65":"1";
    [...simbolosCfg.biblioteca.querySelectorAll("button[data-id]")].forEach(btn=>{btn.disabled=sistema});
  }
  if(simbolosCfg.modalOk){simbolosCfg.modalOk.disabled=false;simbolosCfg.modalOk.style.opacity="1"}
}
function simbolosSelecionarBiblioteca(id){
  if(simbolosModalEhSistema())return;
  const item=simbolosBibliotecaCache.find(x=>x.id===Number(id));
  if(!item||!simbolosCfg)return;
  simbolosLimparImagemEditada();
  simbolosSetModalRefId(item.id);
  simbolosSetModalCodigo(item.codigo||item.icone||"");
  if(simbolosCfg.modalNome)simbolosCfg.modalNome.value=String(item.descricao||"").trim();
  if(simbolosCfg.modalEspecialidade){
    const espRaw=item?.especialidade!=null?String(item.especialidade):"";
    const esp=simbolosEspecialidadeResolverValor(espRaw)||espRaw||simbolosEspecialidadePadrao();
    simbolosCfg.modalEspecialidade.value=esp;
  }
  simbolosSetModalForma(item?.tipo_marca);
  if(Number(item?.id||0)>0&&!simbolosEhSistema(item)){
    simbolosCfg.modalBackdrop.dataset.editId=String(item.id);
  }else{
    delete simbolosCfg.modalBackdrop.dataset.editId;
  }
  if(String(item?.imagem_custom||"").trim()){
    simbolosAplicarImagemEditada(String(item.imagem_custom));
  }else{
    simbolosAtualizarPreview(item.codigo||item.icone||"");
  }
  simbolosAplicarModoModal(item);
  simbolosAtualizarSelecaoBiblioteca({id:Number(id||0)});
}
function simbolosTipoSelecionado(){const radios=[...simbolosCfg.modalBackdrop.querySelectorAll("input[name='simbolos-tipo']")];const r=radios.find(x=>x.checked);return r&&r.value==="sistema"?1:2}
function simbolosFecharEditor(){if(!simbolosCfg?.editorBackdrop)return;simbolosCfg.editorBackdrop.classList.add("hidden");if(simbolosCfg.editorFrame)simbolosCfg.editorFrame.src="about:blank"}
function simbolosAbrirEditor(url){if(!simbolosCfg?.editorBackdrop||!simbolosCfg?.editorFrame)return;simbolosCfg.editorFrame.src=url;simbolosCfg.editorBackdrop.classList.remove("hidden")}
function simbolosAbrirModal(modo){
  if(!simbolosCfg)return;
  const editar=modo==="editar";
  const item=editar?simbolosSelecionadoNaGrade():null;
  const codigoAtual=String(item?.codigo||"").trim();
  simbolosLimparImagemEditada();
  simbolosFecharEditor();
  simbolosCfg.modalTitle.textContent="Edita simbolo grafico";
  simbolosCfg.modalBackdrop.dataset.editId=editar&&item?String(item.id):"";
  simbolosSetModalRefId(editar&&item?Number(item.id||0):0);
  simbolosCfg.modalNome.value=editar?String(item?.descricao||""):"";
  const espRaw=editar&&item?.especialidade!=null?String(item.especialidade):"";
  simbolosCfg.modalEspecialidade.value=simbolosEspecialidadeResolverValor(espRaw)||espRaw||simbolosEspecialidadePadrao();
  simbolosSetModalForma(editar?item?.tipo_marca:null);
  simbolosSetModalCodigo(editar?codigoAtual:"");
  simbolosAtualizarSelecaoBiblioteca(editar?{id:Number(item?.id||0),codigo:codigoAtual}:{});
  simbolosAtualizarPreview(editar?codigoAtual:"");
  if(editar&&item?.imagem_custom){
    simbolosAplicarImagemEditada(String(item.imagem_custom));
  }
  simbolosAplicarModoModal(editar?item:null);
  const btnClear=simbolosCfg.modalBackdrop?.querySelector("#simbolos-desenho-clear");
  if(btnClear)btnClear.onclick=async()=>{
    if(!simbolosCfg||simbolosModalEhSistema())return;
    const excluiu=await simbolosExcluirModalAtual();
    if(excluiu)return;
    const nomeSimbolo=String(simbolosCfg?.modalNome?.value||item?.descricao||"").trim()||"este simbolo";
    const codigo=String(simbolosCodigoSelecionado()||"").trim();
    const temImagemCustom=!!String(simbolosCfg?.modalBackdrop?.dataset?.customImage||"").trim();
    if(!codigo&&!temImagemCustom)return;
    const confirmou=await simbolosDialogPergunta(`Deseja eliminar o desenho do simbolo ${nomeSimbolo}?`);
    if(!confirmou)return;
    simbolosLimparImagemEditada();
    simbolosSetModalCodigo("");
    simbolosSetModalRefId(0);
    simbolosAtualizarSelecaoBiblioteca({});
    simbolosAtualizarPreview("");
  };
  const btnEdit=simbolosCfg.modalBackdrop?.querySelector("#simbolos-desenho-edit");
  if(btnEdit)btnEdit.onclick=async()=>{
    if(simbolosModalEhSistema())return;
    const codigo=String(simbolosCodigoSelecionado()||codigoAtual||"").trim();
    const refId=simbolosRefIdSelecionado();
    const itemAtual=(refId?(simbolosBibliotecaCache.find(x=>Number(x.id||0)===refId)||simbolosCache.find(x=>Number(x.id||0)===refId)||null):null)||(codigo?simbolosBibliotecaCache.find(x=>String(x.codigo||x.icone||"").trim().toLowerCase()===codigo.toLowerCase()):null)||simbolosCache.find(x=>String(x.codigo||x.icone||"").trim().toLowerCase()===codigo.toLowerCase())||item||null;
    const especialidadeTexto=simbolosCfg?.modalEspecialidade?.selectedOptions?.[0]?.textContent?.trim()||simbolosEspecialidadeNome(itemAtual?.especialidade)||"";
    const formaTexto=simbolosCfg?.modalForma?.selectedOptions?.[0]?.textContent?.trim()||"";
    const nomeAtual=(simbolosCfg?.modalNome?.value||"").trim();
    const imageUrl=String(simbolosCfg?.modalBackdrop?.dataset?.customImage||"").trim()||simbolosImagemUrl(itemAtual)||"";
    const editorUrl=new URL("/frontend/mock_simbolo_editor.html",window.location.origin);
    if(nomeAtual)editorUrl.searchParams.set("nome",nomeAtual);
    if(especialidadeTexto)editorUrl.searchParams.set("especialidade",especialidadeTexto);
    if(formaTexto)editorUrl.searchParams.set("forma",formaTexto);
    if(codigo)editorUrl.searchParams.set("codigo",codigo);
    if(imageUrl)editorUrl.searchParams.set("image",imageUrl);
    simbolosAbrirEditor(editorUrl.toString());
  };
  simbolosCfg.modalBackdrop.classList.remove("hidden");
}
async function simbolosSalvarModal(){
  const resultado=await simbolosPersistirEdicao({
    nome:simbolosCfg?.modalNome?.value||"",
    especialidade:simbolosCfg?.modalEspecialidade?.selectedOptions?.[0]?.textContent||"",
    forma:simbolosCfg?.modalForma?.selectedOptions?.[0]?.textContent||"",
    image:String(simbolosCfg?.modalBackdrop?.dataset?.customImage||"").trim()||null,
  });
  if(!resultado.ok){
    window.alert(resultado.message||"Falha ao salvar simbolo.");
    return;
  }
  if(resultado.created){
    await simbolosDialogInfo("Lembre-se: Para utilizar o novo simbolo, voce deve associa-lo a uma intervencao no modulo Configura - Tabelas de precos.");
  }
  simbolosFecharEditor();
  simbolosFecharModal();
}
async function simbolosExcluirSelecionado(){const item=simbolosSelecionadoNaGrade();if(!item){window.alert("Selecione um simbolo.");return}simbolosSelId=Number(item.id||0)||simbolosSelId;if(simbolosEhSistema(item)){window.alert("Simbolos de sistema nao podem ser excluidos.");return}const nome=String(item.descricao||"").trim()||"este simbolo";if(!window.confirm(`Deseja eliminar o simbolo \"${nome}\"?`))return;const{res,data}=await requestJson("DELETE",`/cadastros/simbolos-graficos/${item.id}`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao eliminar simbolo.");return}simbolosRemoverDoCache(item.id);await simbolosCarregar()}
function simbolosVincularEventos(){if(!simbolosCfg||simbolosCfg.panel.dataset.bound==="1")return;simbolosCfg.panel.dataset.bound="1";bindStandardGridActivation(simbolosCfg.tbody,simbolosSelecionarLinha,()=>{if(!simbolosSelecionado()){window.alert("Selecione um simbolo.");return}simbolosAbrirModal("editar")});simbolosCfg.btnNovo.addEventListener("click",()=>simbolosAbrirModal("novo"));simbolosCfg.btnEditar.addEventListener("click",()=>{if(!simbolosSelecionado()){window.alert("Selecione um simbolo.");return}simbolosAbrirModal("editar")});simbolosCfg.btnExcluir.addEventListener("click",simbolosExcluirSelecionado);simbolosCfg.btnFechar.addEventListener("click",()=>{simbolosFecharEditor();simbolosCfg.panel.classList.add("hidden");workspaceEmpty.classList.remove("hidden")});if(simbolosCfg.modalCancelar)simbolosCfg.modalCancelar.addEventListener("click",()=>{simbolosFecharEditor();simbolosFecharModal()});if(simbolosCfg.modalOk)simbolosCfg.modalOk.addEventListener("click",simbolosSalvarModal);if(simbolosCfg.modalBackdrop)simbolosCfg.modalBackdrop.addEventListener("click",ev=>{if(ev.target===simbolosCfg.modalBackdrop){simbolosFecharEditor();simbolosFecharModal()}});if(simbolosCfg.editorBackdrop)simbolosCfg.editorBackdrop.addEventListener("click",ev=>{if(ev.target===simbolosCfg.editorBackdrop)simbolosFecharEditor()});if(simbolosCfg.biblioteca)simbolosCfg.biblioteca.addEventListener("click",ev=>{const btn=ev.target.closest("button[data-id]");if(!btn)return;simbolosSelecionarBiblioteca(btn.dataset.id)});if(simbolosCfg.msgSim)simbolosCfg.msgSim.onclick=()=>simbolosDialogFechar(true);if(simbolosCfg.msgNao)simbolosCfg.msgNao.onclick=()=>simbolosDialogFechar(false);if(simbolosCfg.msgBackdrop)simbolosCfg.msgBackdrop.addEventListener("click",ev=>{if(ev.target===simbolosCfg.msgBackdrop)simbolosDialogFechar(false)})}
window.addEventListener("message",async ev=>{
  if(ev.origin!==window.location.origin)return;
  const data=ev.data||{};
  if(data.type==="simbolo-editor-close"){
    simbolosFecharEditor();
    return;
  }
  if(data.type!=="simbolo-editor-save")return;
  if(!simbolosCfg?.modalBackdrop||simbolosCfg.modalBackdrop.classList.contains("hidden"))return;
  const codigoAtual=String(simbolosCodigoSelecionado()||"").trim();
  const codigoMsg=String(data.codigo||"").trim();
  if(codigoMsg&&codigoAtual&&codigoMsg.toLowerCase()!==codigoAtual.toLowerCase())return;
  const resultado=await simbolosPersistirEdicao(data);
  if(!resultado.ok){
    simbolosEditorNotificar("simbolo-editor-error",{message:resultado.message||"Falha ao salvar simbolo."});
    return;
  }
  if(resultado.created){
    await simbolosDialogInfo("Lembre-se: Para utilizar o novo simbolo, voce deve associa-lo a uma intervencao no modulo Configura - Tabelas de precos.");
  }
  simbolosEditorNotificar("simbolo-editor-saved",{message:resultado.message||"Desenho salvo com sucesso."});
  simbolosFecharEditor();
});

// Overrides - Anamnese CRUD
function anamneseEnsureUI(){const existingPanel=document.getElementById("anamnese-panel");if(!existingPanel){const style=document.createElement("style");style.textContent=".anamnese-panel{width:min(760px,100%);min-height:0;height:fit-content;align-self:start;padding:10px 10px 8px;background:#fff;border:1px solid #cfd8e3;box-sizing:border-box;font:12px Tahoma,sans-serif}.anamnese-toolbar{display:flex;gap:8px;align-items:center;margin:6px 0 6px;flex-wrap:wrap}.anamnese-toolbar .sep{width:1px;height:26px;background:#cfd8e3;margin:0 4px}.anamnese-grid{border:1px solid #cfd8e3;height:420px;overflow:auto;background:#fff}.anamnese-grid table{width:100%;border-collapse:collapse;table-layout:fixed}.anamnese-grid th,.anamnese-grid td{border-bottom:1px solid #edf1f6;padding:3px 6px;height:22px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.anamnese-grid th{background:#f2f6fb;font:700 12px Tahoma,sans-serif;text-align:left}.anamnese-grid tr.selected{background:#d9e8fb}.anamnese-top{display:flex;align-items:center;gap:8px;flex-wrap:wrap}.anamnese-top label{white-space:nowrap}.anamnese-top select{height:24px;border:1px solid #bfc9d6;padding:0 6px;box-sizing:border-box}.anamnese-subtoolbar{display:flex;gap:8px;align-items:center;margin:6px 0 6px;flex-wrap:wrap}.anamnese-total{margin-top:6px;color:#5b6b7e}.anamnese-modal .f{margin-bottom:6px}";document.head.appendChild(style);workspaceEmpty.insertAdjacentHTML("afterend",`<section id="anamnese-panel" class="anamnese-panel hidden"><div class="panel-title">Configura questionários de anamnese</div><div class="anamnese-top"><label for="anamnese-questionario">Questionário:</label><select id="anamnese-questionario"></select><div class="anamnese-toolbar"><button id="anamnese-btn-novo" class="materiais-btn" type="button"><img src="/desktop-assets/novo.png" alt="">Novo...</button><button id="anamnese-btn-editar" class="materiais-btn" type="button"><img src="/desktop-assets/editar.png" alt="">Altera...</button><button id="anamnese-btn-excluir" class="materiais-btn" type="button"><img src="/desktop-assets/eliminar.png" alt="">Elimina</button><span class="sep"></span><button id="anamnese-btn-imprimir" class="materiais-btn" type="button"><img src="/desktop-assets/imprime.png" alt="">Imprime...</button><button id="anamnese-btn-fechar" class="materiais-btn" type="button"><img src="/desktop-assets/cancela.png" alt="">Fecha</button></div></div><div class="anamnese-subtoolbar"><button id="anamnese-btn-nova-pergunta" class="materiais-btn" type="button"><img src="/desktop-assets/novo.png" alt="">Nova pergunta...</button><button id="anamnese-btn-alterar-pergunta" class="materiais-btn" type="button"><img src="/desktop-assets/editar.png" alt="">Altera...</button><button id="anamnese-btn-excluir-pergunta" class="materiais-btn" type="button"><img src="/desktop-assets/eliminar.png" alt="">Elimina</button><span class="sep"></span><button id="anamnese-btn-renumerar" class="materiais-btn" type="button">1,2... Renumera perguntas</button></div><div class="anamnese-grid"><table><colgroup><col style="width:46px"><col></colgroup><thead><tr><th>Nº</th><th>Texto da pergunta</th></tr></thead><tbody id="anamnese-tbody"></tbody></table></div><div id="anamnese-total" class="anamnese-total">0 perguntas</div></section>`)}if(!document.getElementById("anamnese-modal-questionario-backdrop")){workspaceEmpty.insertAdjacentHTML("afterend",`<div id="anamnese-modal-questionario-backdrop" class="cad-modal-backdrop hidden"><div class="cad-modal anamnese-modal"><div class="modal-header"><div id="anamnese-modal-questionario-title" class="modal-title">Questionário</div></div><div class="f"><label>Nome</label><input id="anamnese-modal-questionario-nome"></div><div class="cad-modal-actions"><button id="anamnese-modal-questionario-ok" class="materiais-btn" type="button"><img src="/desktop-assets/gravar.png" alt="">Ok</button><button id="anamnese-modal-questionario-cancelar" class="materiais-btn" type="button"><img src="/desktop-assets/cancela.png" alt="">Cancela</button></div></div></div><div id="anamnese-modal-pergunta-backdrop" class="cad-modal-backdrop hidden"><div class="cad-modal anamnese-modal"><div class="modal-header"><div id="anamnese-modal-pergunta-title" class="modal-title">Pergunta</div></div><div class="f"><label>Nº</label><input id="anamnese-modal-pergunta-numero" type="number" min="1" step="1"></div><div class="f"><label>Texto</label><input id="anamnese-modal-pergunta-texto"></div><div class="cad-modal-actions"><button id="anamnese-modal-pergunta-ok" class="materiais-btn" type="button"><img src="/desktop-assets/gravar.png" alt="">Ok</button><button id="anamnese-modal-pergunta-cancelar" class="materiais-btn" type="button"><img src="/desktop-assets/cancela.png" alt="">Cancela</button></div></div></div>`)}anamneseCfg={panel:document.getElementById("anamnese-panel"),tbody:document.getElementById("anamnese-tbody"),total:document.getElementById("anamnese-total"),cboQuestionario:document.getElementById("anamnese-questionario"),btnNovo:document.getElementById("anamnese-btn-novo"),btnEditar:document.getElementById("anamnese-btn-editar"),btnExcluir:document.getElementById("anamnese-btn-excluir"),btnImprimir:document.getElementById("anamnese-btn-imprimir"),btnFechar:document.getElementById("anamnese-btn-fechar"),btnNovaPergunta:document.getElementById("anamnese-btn-nova-pergunta"),btnAlterarPergunta:document.getElementById("anamnese-btn-alterar-pergunta"),btnExcluirPergunta:document.getElementById("anamnese-btn-excluir-pergunta"),btnRenumera:document.getElementById("anamnese-btn-renumerar"),modalQBackdrop:document.getElementById("anamnese-modal-questionario-backdrop"),modalQTitle:document.getElementById("anamnese-modal-questionario-title"),modalQNome:document.getElementById("anamnese-modal-questionario-nome"),modalQOk:document.getElementById("anamnese-modal-questionario-ok"),modalQCancelar:document.getElementById("anamnese-modal-questionario-cancelar"),modalPBackdrop:document.getElementById("anamnese-modal-pergunta-backdrop"),modalPTitle:document.getElementById("anamnese-modal-pergunta-title"),modalPNumero:document.getElementById("anamnese-modal-pergunta-numero"),modalPTexto:document.getElementById("anamnese-modal-pergunta-texto"),modalPOk:document.getElementById("anamnese-modal-pergunta-ok"),modalPCancelar:document.getElementById("anamnese-modal-pergunta-cancelar")};if(anamneseCfg.modalQBackdrop)ensureModalChrome(anamneseCfg.modalQBackdrop.querySelector(".cad-modal"));if(anamneseCfg.modalPBackdrop)ensureModalChrome(anamneseCfg.modalPBackdrop.querySelector(".cad-modal"))}
function anamneseRender(){if(!anamneseCfg)return;anamneseCfg.tbody.innerHTML=anamneseCache.map(x=>`<tr data-id="${x.id}" class="${x.id===anamneseSelId?"selected":""}"><td>${x.numero}</td><td>${esc(x.texto)}</td></tr>`).join("");anamneseCfg.total.textContent=`${anamneseCache.length} perguntas`}
function anamneseSelecionado(){return anamneseCache.find(x=>x.id===anamneseSelId)||null}
function anamneseQuestionarioSelecionado(){return anamneseQuestionariosCache.find(x=>x.id===anamneseQuestionarioSelId)||null}
function anamneseRenderQuestionarios(){if(!anamneseCfg)return;anamneseCfg.cboQuestionario.innerHTML=anamneseQuestionariosCache.map(q=>`<option value="${q.id}">${esc(q.nome||"")}</option>`).join("");if(!anamneseQuestionariosCache.length){anamneseCfg.cboQuestionario.innerHTML="<option value=\"\">Sem questionário</option>";anamneseQuestionarioSelId=null;return}const existe=anamneseQuestionariosCache.some(x=>x.id===anamneseQuestionarioSelId);if(!existe)anamneseQuestionarioSelId=anamneseQuestionariosCache[0].id;anamneseCfg.cboQuestionario.value=String(anamneseQuestionarioSelId)}
async function anamneseCarregarQuestionarios(){const{res,data}=await requestJson("GET","/anamnese/questionarios",undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao carregar questionários.");return}anamneseQuestionariosCache=Array.isArray(data)?data:[];anamneseRenderQuestionarios()}
async function anamneseCarregarPerguntas(){if(!anamneseQuestionarioSelId){anamneseCache=[];anamneseSelId=null;anamneseRender();return}const{res,data}=await requestJson("GET",`/anamnese/questionarios/${anamneseQuestionarioSelId}/perguntas`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao carregar perguntas.");return}anamneseCache=Array.isArray(data)?data:[];anamneseSelId=anamneseCache[0]?.id||null;anamneseRender()}
function anamneseAbrirModalQuestionario(modo){if(!anamneseCfg)return;const editar=modo==="editar";const item=editar?anamneseQuestionarioSelecionado():null;anamneseCfg.modalQBackdrop.dataset.editId=editar&&item?String(item.id):"";anamneseCfg.modalQTitle.textContent=editar?"Alterar questionário":"Novo questionário";anamneseCfg.modalQNome.value=item?.nome||"";anamneseCfg.modalQBackdrop.classList.remove("hidden")}
function anamneseFecharModalQuestionario(){if(!anamneseCfg)return;anamneseCfg.modalQBackdrop.classList.add("hidden")}
async function anamneseSalvarQuestionario(){const nome=(anamneseCfg.modalQNome.value||"").trim();if(!nome){window.alert("Informe o nome do questionário.");return}const editId=Number(anamneseCfg.modalQBackdrop.dataset.editId||0)||null;const payload={nome,ativo:true};const method=editId?"PUT":"POST";const path=editId?`/anamnese/questionarios/${editId}`:"/anamnese/questionarios";const{res,data}=await requestJson(method,path,payload,true);if(!res.ok){window.alert(data.detail||"Falha ao salvar questionário.");return}await anamneseCarregarQuestionarios();await anamneseCarregarPerguntas();anamneseFecharModalQuestionario()}
async function anamneseExcluirQuestionario(){const item=anamneseQuestionarioSelecionado();if(!item){window.alert("Selecione um questionário.");return}if(!window.confirm(`Deseja eliminar o questionário \"${item.nome}\"?`))return;const{res,data}=await requestJson("DELETE",`/anamnese/questionarios/${item.id}`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao eliminar questionário.");return}anamneseQuestionarioSelId=null;await anamneseCarregarQuestionarios();await anamneseCarregarPerguntas()}
function anamneseAbrirModalPergunta(modo){if(!anamneseCfg)return;const editar=modo==="editar";const item=editar?anamneseSelecionado():null;anamneseCfg.modalPBackdrop.dataset.editId=editar&&item?String(item.id):"";anamneseCfg.modalPTitle.textContent=editar?"Alterar pergunta":"Nova pergunta";anamneseCfg.modalPNumero.value=item?.numero||"";anamneseCfg.modalPTexto.value=item?.texto||"";anamneseCfg.modalPBackdrop.classList.remove("hidden")}
function anamneseFecharModalPergunta(){if(!anamneseCfg)return;anamneseCfg.modalPBackdrop.classList.add("hidden")}
async function anamneseSalvarPergunta(){if(!anamneseQuestionarioSelId){window.alert("Selecione um questionário.");return}const numeroTxt=(anamneseCfg.modalPNumero.value||"").trim();const numero=numeroTxt?Number(numeroTxt):null;const texto=(anamneseCfg.modalPTexto.value||"").trim();if(!texto){window.alert("Informe o texto da pergunta.");return}const editId=Number(anamneseCfg.modalPBackdrop.dataset.editId||0)||null;const payload={numero,texto,ativo:true};const method=editId?"PUT":"POST";const path=editId?`/anamnese/perguntas/${editId}`:`/anamnese/questionarios/${anamneseQuestionarioSelId}/perguntas`;const{res,data}=await requestJson(method,path,payload,true);if(!res.ok){window.alert(data.detail||"Falha ao salvar pergunta.");return}await anamneseCarregarPerguntas();anamneseFecharModalPergunta()}
async function anamneseExcluirPergunta(){const item=anamneseSelecionado();if(!item){window.alert("Selecione uma pergunta.");return}if(!window.confirm(`Eliminar a pergunta ${item.numero}?`))return;const{res,data}=await requestJson("DELETE",`/anamnese/perguntas/${item.id}`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao eliminar pergunta.");return}await anamneseCarregarPerguntas()}
async function anamneseRenumeraPerguntas(){if(!anamneseQuestionarioSelId){window.alert("Selecione um questionário.");return}const{res,data}=await requestJson("POST",`/anamnese/questionarios/${anamneseQuestionarioSelId}/renumerar`,{},true);if(!res.ok){window.alert(data.detail||"Falha ao renumerar perguntas.");return}await anamneseCarregarPerguntas()}
function anamneseVincularEventos(){if(!anamneseCfg||anamneseCfg.panel.dataset.bound==="1")return;anamneseCfg.panel.dataset.bound="1";anamneseCfg.tbody.addEventListener("click",ev=>{const tr=ev.target.closest("tr[data-id]");if(!tr)return;anamneseSelId=Number(tr.dataset.id||0)||null;anamneseRender()});anamneseCfg.cboQuestionario.addEventListener("change",async ev=>{anamneseQuestionarioSelId=Number(ev.target.value||0)||null;await anamneseCarregarPerguntas()});anamneseCfg.btnNovo.addEventListener("click",()=>anamneseAbrirModalQuestionario("novo"));anamneseCfg.btnEditar.addEventListener("click",()=>{if(!anamneseQuestionarioSelecionado()){window.alert("Selecione um questionário.");return}anamneseAbrirModalQuestionario("editar")});anamneseCfg.btnExcluir.addEventListener("click",anamneseExcluirQuestionario);anamneseCfg.btnImprimir.addEventListener("click",()=>window.alert("Imprimir questionário: em planejamento."));anamneseCfg.btnFechar.addEventListener("click",()=>{anamneseCfg.panel.classList.add("hidden");workspaceEmpty.classList.remove("hidden")});anamneseCfg.btnNovaPergunta.addEventListener("click",()=>anamneseAbrirModalPergunta("novo"));anamneseCfg.btnAlterarPergunta.addEventListener("click",()=>{if(!anamneseSelecionado()){window.alert("Selecione uma pergunta.");return}anamneseAbrirModalPergunta("editar")});anamneseCfg.btnExcluirPergunta.addEventListener("click",anamneseExcluirPergunta);anamneseCfg.btnRenumera.addEventListener("click",anamneseRenumeraPerguntas);anamneseCfg.modalQCancelar.addEventListener("click",anamneseFecharModalQuestionario);anamneseCfg.modalQOk.addEventListener("click",anamneseSalvarQuestionario);anamneseCfg.modalQBackdrop.addEventListener("click",ev=>{if(ev.target===anamneseCfg.modalQBackdrop)anamneseFecharModalQuestionario()});anamneseCfg.modalPCancelar.addEventListener("click",anamneseFecharModalPergunta);anamneseCfg.modalPOk.addEventListener("click",anamneseSalvarPergunta);anamneseCfg.modalPBackdrop.addEventListener("click",ev=>{if(ev.target===anamneseCfg.modalPBackdrop)anamneseFecharModalPergunta()})}
async function anamneseAbrir(){anamneseEnsureUI();anamneseVincularEventos();hideAllPanels();ensurePanelChrome(anamneseCfg.panel);anamneseCfg.panel.classList.remove("hidden");workspaceEmpty.classList.add("hidden");await anamneseCarregarQuestionarios();await anamneseCarregarPerguntas();footerMsg.textContent="Configuração de anamnese aberta."}




